(24, '7d06dcdb-5aaf-11f1-b13b-52cb7e509645', 'Đề thi thử TOEIC: Mã đề FEVER | Thi thử TOEIC Online', null, 7200, '/server/uploads/audio/main_rGK2OwYGZ3.mp3', 200, 0, 1);
insert into `passages` (`id`, `test_id`, `content`, `translation`, `translation_en`, `audio_url`, `image_url`) values
(541, 24, 'Questions 32 - 34:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Bạn nghĩ sao? Nó có hay như quảng cáo không?<br></span>\n<span class=\"paragraph-sentence\">Ừ, tôi nghĩ vậy. Dan Brown thì quá tuyệt; anh ấy đúng là một diễn viên tuyệt vời! Và tôi nghĩ là nghệ thuật quay phim thì đẹp đến mê hồn! Vậy còn bạn thì sao?<br></span>\n<span class=\"paragraph-sentence\">Đúng là nó được quay rất đẹp, và Brown luôn xuất sắc trong những vai ông đóng. Nhưng nhìn chung thì tôi hơi thất vọng đấy. Cốt truyện hơi loãng. Nhìn chung, tôi không nghĩ bộ phim đã đáp ứng được kỳ vọng của quảng cáo.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">-- What did you think? Was it as good as advertised?<br></span>\n<span class=\"paragraph-sentence\">-- Yeah, I thought so. <span class=\"q404-1\">Tory Brown was fantastic; he\'s such a superb actor!</span> And I thought the cinematography was breath-taking! How about you?<br></span>\n<span class=\"paragraph-sentence\">-- It was beautifully filmed, all right, and Brown is the best at what he does. <span class=\"q405-1\">But overall I was rather disappointed.</span> The plot was kind of thin. Overall, I don\'t think the film lived up to its hype.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/5NQKl.mp3', null),
(542, 24, 'Questions 35 - 37:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Này Chris. Mọi thứ thế nào rồi? Bạn đã đặt xong cái tường thạch cao lên chưa?</span>\n<span class=\"paragraph-sentence\">Chưa. Tôi không nghĩ rằng tôi sẽ làm xong trong một vài giờ tới. Tôi vẫn còn có sáu cái ở đây và bốn cái khác cho phòng vệ sinh ở đó. Mà sao thế?</span>\n<span class=\"paragraph-sentence\">Thực ra, tôi cần bạn giúp dán giấy dán tường ở phòng khách. Tôi sẽ không lấy nhiều thời gian của bạn đâu. Với lại 11 giờ 30 rồi. Cũng sắp tới giờ ăn trưa rồi!</span>\n<span class=\"paragraph-sentence\">Được rồi. Tôi nghĩ là tôi có thể bỏ ra một chút ít thời gian trước giờ ăn trưa. Cùng đi nào.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">W: Hey, Chris. How’s it going? Are you done putting up the drywall?</span>\n<span class=\"paragraph-sentence\">M: Not yet. I don’t think I’ll be done for another couple of hours. <span class=\"q1538-1\">I still have six here and another four for the restroom over there.</span> Why?</span>\n<span class=\"paragraph-sentence\">W: Actually, I need your help putting on the wallpaper for the living room. I won’t take up much of your time. Besides, it’s 11:30. It’s almost lunchtime!</span>\n<span class=\"paragraph-sentence\">M: Okay. I guess I can spare some time before lunch. Let’s go and take a look.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/glHeY.mp3', '/server/uploads/image/de-thi-thu-toeic-ma-de-fever-thi-thu-toeic-online/question_35_37.png'),
(543, 24, 'Questions 38 - 40:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">W: Vâng, để tôi xem xem liệu tôi đã làm mọi thứ rõ ràng chưa. Chuyến bay của bạn sẽ cất cánh vào thứ ba tới ngày 20 tháng sáu lúc 4 giờ 50 chiều. Bạn sẽ ở một đêm tại Hilton Hills và sẽ đi chuyến bay 11 giờ đến London, phải chứ?<br></span>\n<span class=\"paragraph-sentence\">M: Chính xác là thế. Tôi sẽ ở một đêm tại Paris để gặp ông Chretien ngay đầu sáng thứ tư nhằm sắp đặt một số chuyện trước khi tôi đi đến London để chốt một thỏa thuận với ông Charles Connery. Tôi cần đảm bảo bạn có tất cả các tài liệu sẵn sàng trước khi tôi tới đó.<br></span>\n<span class=\"paragraph-sentence\">W: Không vấn đề. Tôi cũng đã gọi ông Chretien và nói ông ấy rằng bạn sẽ đến để gặp ông ấy, và ông ta cũng nói mình sẽ chuẩn bị sẵn sàng tất cả các tài liệu cần cho bạn luôn.<br></span>\n<span class=\"paragraph-sentence\">M: Tuyệt thật. Tôi có một linh tính rằng mình sẽ ký được hợp đồng này. Tôi cảm thấy rất tốt về điều đó.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">W: Okay, let me see if I have everything straight here. Your flight is due to arrive next Tuesday on June 20 at 4:50 p.m. You will spend one night at the Hilton Hills and be on the 11 o\'clock flight out to London, right?<br></span>\n<span class=\"paragraph-sentence\">M: That\'s correct. <span class=\"q2035-1\"><span class=\"q2037-1\">I will spend a night in Paris to meet with Mr. Chretien the first thing Wednesday morning to settle a couple of things before I set out to London to close a deal with Mr. Charles Connery.</span></span> <span class=\"q2036-1\">I need to make sure you have all the documents ready for me when I get there.</span><br></span>\n<span class=\"paragraph-sentence\">W: No problem. I\'ve also called Mr. Chretien and told him that you will be coming to see him, and he said he will have all the necessary documents ready for you as well.<br></span>\n<span class=\"paragraph-sentence\">M: That\'s great. I have a gut feeling that I am going to land this contract. I feel very good about it.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/XXZei.mp3', null),
(544, 24, 'Questions 41 - 43:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">W: Anh có thể cho tôi biết mấy giờ thì chuyến xe buýt đi Los Angeles tiếp theo sẽ rời khỏi?<br></span>\n<span class=\"paragraph-sentence\">M: Nó chạy mỗi 15 phút một lần. Cô vừa lỡ chuyến lúc 11 giờ. <br></span>\n<span class=\"paragraph-sentence\">W: Oh, tệ thật. Nó khởi hành ở đâu vậy?<br></span>\n<span class=\"paragraph-sentence\">M: Trạm số 13. Cô có thể đợi ở đó.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">W: <span class=\"q1078-1\">Can you tell me what time the next bus for Los Angeles leaves?</span><br></span>\n<span class=\"paragraph-sentence\">M: <span class=\"q1079-1\">It runs every fifteen minutes. You just missed the eleven o\'clock bus.</span> <br></span>\n<span class=\"paragraph-sentence\">W: Oh, that\'s too bad. Where does it leave from?<br></span>\n<span class=\"paragraph-sentence\">M: <span class=\"q1080-1\">Stand thirteen.</span> You can wait over there.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/FZ0qo.mp3', null),
(545, 24, 'Questions 44 - 46:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: Khi nào cô đi dự hội thảo lớn? <br></span>\n<span class=\"paragraph-sentence\">W: Sáng mai. Hội thảo ở New York. <br></span>\n<span class=\"paragraph-sentence\">M: Cô sẽ ở đó bao lâu?<br></span>\n<span class=\"paragraph-sentence\">W: Chỉ hai đêm. Tôi sẽ trở về vào tối thứ Sáu.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: <span class=\"q946-1\">When do you leave for the big conference?</span> <br></span>\n<span class=\"paragraph-sentence\">W: <span class=\"q948-2\">Tomorrow morning.</span> <span class=\"q947-1\">It\'s in New York.</span> <br></span>\n<span class=\"paragraph-sentence\">M: How long will you stay there?<br></span>\n<span class=\"paragraph-sentence\">W: <span class=\"q948-1\">Just two nights. I\'ll be back on Friday evening.</span></span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/TxjQy.mp3', null),
(546, 24, 'Questions 47 - 49:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Người đàn ông: Chào mừng đến với Hội trường âm nhạc Dolby. Tôi có thể xem vé của bạn được không?<br></span>\n<span class=\"paragraph-sentence\">Người phụ nữ: Của bạn đây. Tôi thực sự mong đợi màn trình diễn này. Karl Teller là một trong những nhạc sĩ yêu thích của tôi và tôi là người ủng hộ lâu năm của Quỹ Đường dây hỗ trợ.<br></span>\n<span class=\"paragraph-sentence\">Người đàn ông: Điều đó thật tuyệt. Đây là lần gây quỹ thứ hai mà chúng tôi tổ chức cho nhóm đó. Được rồi, bạn ở ghế 122, nằm trong khu D. Chỉ cần đi qua cổng chính và một người chỉ chỗ sẽ hỗ trợ bạn. Chương trình sẽ bắt đầu lúc bảy giờ rưỡi.<br></span>\n<span class=\"paragraph-sentence\">Người phụ nữ: Cảm ơn bạn. Tôi có được phép mang đồ uống vào khán phòng không? Tôi định dừng lại ở quán ăn vặt.<br></span>\n<span class=\"paragraph-sentence\">Hẳn rồi. Nhưng xin lưu ý rằng không được phép chụp ảnh và bạn nên để điện thoại ở chế độ im lặng để không làm phiền người khác.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: Welcome to the Dolby Music Hall. May I see your ticket, please?<br></span>\n<span class=\"paragraph-sentence\">W: Here you go. I\'m really looking forward to this performance. Karl Teller is one of my favorite musicians, and I\'m a longtime supporter of The Helpline Foundation.<br></span>\n<span class=\"paragraph-sentence\">M: That\'s great. <span class=\"q2149-1\">This is the second fundraiser that we\'ve held for that group</span>. <span class=\"q2150-1\">OK, you\'re in seat 122, which is in section D</span>. Just head through the main entrance and an usher will assist you. The show will start at half past seven.<br></span>\n<span class=\"paragraph-sentence\">W: Thank you. Am I allowed to bring a beverage into the auditorium? I was planning to stop by the snack bar.<br></span>\n<span class=\"paragraph-sentence\">M: Sure. <span class=\"q2151-1\">But please note that photography is not permitted, and you should keep your cell phone on silent mode so as not to disturb others</span>.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/ETXtq.mp3', '/server/uploads/image/de-thi-thu-toeic-ma-de-fever-thi-thu-toeic-online/question_47_49.png'),
(547, 24, 'Questions 50 - 52:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Người đàn ông: Cảm ơn vì đã tham gia cùng tôi với tư cách là một khách mời đặc biệt trong chương trình nấu ăn của tôi tại phòng thu hình của chúng tôi ngày hôm nay, Wendy. Tôi chắc rằng nhiều khán giả truyền hình của tôi đã mong chờ điều này.<br></span>\n<span class=\"paragraph-sentence\">Người phụ nữ: Không vấn đề gì, thưa đầu bếp Hammond. Vậy, bạn sẽ tạo ra những gì với các thành phần này?<br></span>\n<span class=\"paragraph-sentence\">Người đàn ông: Chà, vì chủ đề của chương trình của chúng ta là các món ăn Ý, tôi sẽ trình bày cách làm mì spaghetti với sốt kem.<br></span>\n<span class=\"paragraph-sentence\">Người phụ nữ: Nghe có vẻ ngon. Ừm, có trứng trộn vào nước sốt, phải không?<br></span>\n<span class=\"paragraph-sentence\">Người đàn ông: Ồ, bạn quen thuộc với món ăn này sao? Công thức cần hai quả trứng. Và đây là một những việc để ghi nhớ. Điều quan trọng là phải giảm nhiệt trên mặt bếp khi thêm trứng để chúng không bị xáo trộn.<br></span>\n<span class=\"paragraph-sentence\">Người phụ nữ: Đó là một mẹo tuyệt vời! Tôi có nên thêm phô mai bây giờ không?<br></span>\n<span class=\"paragraph-sentence\">Người đàn ông: Vâng, làm ơn. Trong khi đó, tôi sẽ cho khán giả thấy sự khác biệt giữa thịt xông khói kiểu Ý và kiểu Mỹ.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: <span class=\"q2284-1\">Thanks for joining me as a special guest on my cooking show here at our broadcasting studio today, Wendy</span>. I\'m sure many of my TV viewers have been looking forward to this.<br></span>\n<span class=\"paragraph-sentence\">W: No problem, Chef Hammond. So, what will you be creating with these ingredients?<br></span>\n<span class=\"paragraph-sentence\">M: Well, since the theme of our program is Italian dishes, I\'ll demonstrate how to make spaghetti with cream sauce.<br></span>\n<span class=\"paragraph-sentence\">W: Sounds delicious. <span class=\"q2285-1\">Um, there are eggs mixed into the sauce, right</span>?<br></span>\n<span class=\"paragraph-sentence\">M: <span class=\"q2285-2\">Oh, you\'re familiar with this dish? The recipe calls for two eggs</span>. And here\'s something to keep in mind. It\'s important to lower the heat on the stovetop when adding the eggs so that they don\'t become scrambled.<br></span>\n<span class=\"paragraph-sentence\">W: That\'s a fantastic tip! Should I add the cheese now?<br></span>\n<span class=\"paragraph-sentence\">M: Yes, please. <span class=\"q2286-1\">Meanwhile, I\'ll show our audience the differences between Italian- and American-style bacon</span>.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/EsW6x.mp3', null),
(548, 24, 'Questions 53 - 55:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Chào Mary! Cô thế nào rồi? Cô đã quyết định liệu có ở lại với chúng tôi 1 năm nữa không?<br></span>\n<span class=\"paragraph-sentence\">Vâng.  Tôi không nghĩ tôi sẽ ở lại. Tôi đã nộp đơn cho một công việc ở trường tiểu học Adams vào năm tới.<br></span>\n<span class=\"paragraph-sentence\">Vậy ư? Thật không? Thật tuyệt, nhưng… tôi đã nghĩ cô thích ở đây. <br></span>\n<span class=\"paragraph-sentence\">Ồ có chứ. Đây là ngôi trường tuyệt vời, và tôi ghét phải rời đi. Vấn đề là, tôi muốn dạy trẻ nhỏ tuổi hơn, và trường Adams có vị trí trống cho giáo viên lớp 2.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">-- Hey Mary! How are you doing? Have you decided whether you\'re going to stay with us another year?<br></span>\n<span class=\"paragraph-sentence\">-- Yes. I don\'t think I will. I\'ve applied for a job at a Adams Elementary for next year.<br></span>\n<span class=\"paragraph-sentence\">--  You have? <span class=\"q569-1\">Really? That\'s great,</span> but...I thought you liked it here.<br></span>\n<span class=\"paragraph-sentence\">-- Oh, I do. This is a great school, and I\'ll hate to leave. <span class=\"q570-1\">The thing is, I\'d really prefer to teach younger children, and Adams has an opening for a second-grade teacher.</span></span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/mloHW.mp3', null),
(549, 24, 'Questions 56 - 58:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: Sếp muốn tôi thay đổi cách sắp đặt của văn phòng chúng ta trước chuyến thăm của chủ tịch vào tháng tới. Ông ấy muốn tôi tận dụng tối đa không gian ở đây bằng cách di chuyển nội thất đi. Tôi không giỏi việc này lắm, nên tôi cần lời khuyên chuyên môn từ bạn. Bạn có thể bỏ chút thời gian để thảo luận về bày trí của văn phòng không?<br></span>\n<span class=\"paragraph-sentence\">W: Ừ thì, tôi khá là bận hôm nay. Để tôi xem... thứ năm này hay thứ hai tới thì ổn với tôi. Bạn thì sao?<br></span>\n<span class=\"paragraph-sentence\">M: Tôi phải rời khỏi thị trấn trong vòng một tuần vào thứ sáu. Tôi nghĩ chúng ta tốt hơn nên họp lại với nhau trước khi tôi đi. Điều đó ổn với bạn chứ?<br></span>\n<span class=\"paragraph-sentence\">W: Điều đó ổn thôi miễn là nó vào buổi sáng. Tôi phải rời đi sớm cho một cuộc hẹn với nha sĩ vào buổi chiều.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: <span class=\"q1852-1\">The boss wants me to change the setting of our office before the president\'s visit next month.</span> He wants me to utilize the space here by moving the furniture around. I am not very good at this, so I need your expert advice. Can you spare some time to discuss the office layout?<br></span>\n<span class=\"paragraph-sentence\">W: Well, I am kind of busy today. <span class=\"q1853-1\">Let me see... this Thursday or next Monday is good for me.</span> What about you?<br></span>\n<span class=\"paragraph-sentence\">M: <span class=\"q1853-2\"><span class=\"q1854-1\">I have to leave town for a week on Friday.</span> I think we\'d better get together before I leave.</span> Is that okay with you?<br></span>\n<span class=\"paragraph-sentence\">W: That will be fine as long as it\'s in the morning. I have to leave early for a dentist appointment in the afternoon.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/IuKAC.mp3', null),
(550, 24, 'Questions 59 - 61:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">(W-Br): Xin chào, tôi đến từ Star Lockmiths. Tôi ở đây để giải quyết về chuyện một cánh cửa không khóa đúng cách.<br></span>\n<span class=\"paragraph-sentence\">(M-Au): Cảm ơn bạn đã đến nhanh như vậy. Đó là một vấn đề an ninh đáng quan ngại rằng rằng trong những cánh cửa của chúng tôi không khóa được.<br></span>\n<span class=\"paragraph-sentence\">(W-Br): Vâng, tôi hiểu. Tôi biết đó là cánh cửa nào, vì vậy tôi sẽ đi ngay qua đó.<br></span>\n<span class=\"paragraph-sentence\">(M-Au): Cảm ơn. Và thật tuyệt nếu điều này có thể được khắc phục trước buổi trưa. Nhân viên làm việc trong các tòa nhà khác sẽ cần sử dụng cánh cửa đó để vào nhà ăn.<br></span>\n<span class=\"paragraph-sentence\">(W-Br): Được rồi, tôi sẽ bắt đầu ngay.<br></span>\n<span class=\"paragraph-sentence\">(M-Au): Cảm ơn bạn. Bạn chỉ cần nhớ là luôn hiển thị thẻ thông hành của bạn.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">(W-Br): Good afternoon, <span class=\"q2380-1\">I\'m from Star Locksmiths</span>. <span class=\"q2380-2\">I\'m here about a door that isn\'t locking properly</span>.<br></span>\n<span class=\"paragraph-sentence\">(M-Au): Thank you for coming so quickly. It\'s a major security concern that one of our doors doesn\'t lock.<br></span>\n<span class=\"paragraph-sentence\">(W-Br): Yes, I understand. I know which door it is, so I\'ll just head over there.<br></span>\n<span class=\"paragraph-sentence\">(M-Au): Thanks. And it\'d be great if this could be fixed before noon. <span class=\"q2381-1\">Employees who work in the other buildings will need to use that door to enter the cafeteria</span>.<br></span>\n<span class=\"paragraph-sentence\">(W-Br): OK, I\'ll get started right away.<br></span>\n<span class=\"paragraph-sentence\">(M-Au): Thank you. <span class=\"q2382-1\">Just remember to keep your visitor\'s badge visible at all time</span>.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/yqyEs.mp3', '/server/uploads/image/de-thi-thu-toeic-ma-de-fever-thi-thu-toeic-online/question_59_61.png'),
(551, 24, 'Questions 62 - 64:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: Đây chắc chắn là nhầm lẫn. Tôi đã gọi điện đặt phòng một tuần trước rồi.<br></span>\n<span class=\"paragraph-sentence\">W: Tôi xin lỗi, nhưng tôi không thấy có phòng nào được đặt dưới tên của anh.<br></span>\n<span class=\"paragraph-sentence\">M: Cô không còn phòng nào cho tôi sao? Tôi cần một phòng trong 3 ngày.<br></span>\n<span class=\"paragraph-sentence\">W: Để xem... Tôi có một phòng nhỏ ở phía sau, và nó chỉ có 165 đô một đêm.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: This must be a mistake. I called to reserve the room a week ago. <br></span>\n<span class=\"paragraph-sentence\">W: I\'m sorry, but <span class=\"q1291-1\">I don\'t see anything here under your name.</span> <br></span>\n<span class=\"paragraph-sentence\">M: Don\'t you have some room you can give me? <span class=\"q1292-1\">I need one for three days.</span> <br></span>\n<span class=\"paragraph-sentence\">W: Let\'s see... I have a small one in back, and <span class=\"q1293-1\">it costs just 165 dollars a night.</span></span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/Q0gz7.mp3', null),
(552, 24, 'Questions 65 - 67:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Người đàn ông (M): Có phải cô để laptop ở tủ trên đầu không?<br></span>\n<span class=\"paragraph-sentence\">Người phụ nữ (W): Ừ, tôi không nghĩ là mình lại có thể dùng nó trên máy bay.<br></span>\n<span class=\"paragraph-sentence\">M: Dĩ nhiên là có thể chứ. Tôi luôn dùng laptop khi bay.<br></span>\n<span class=\"paragraph-sentence\">W: Tôi quá mệt để làm điều đó. Tôi nghĩ mình sẽ đi ngủ một tí.<br></span>\n<span class=\"paragraph-sentence\">M: À, tôi thì đói, tôi hi vọng là họ có phục vụ đồ ăn trên chuyến bay này.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Man: Did you put your laptop in the overhead compartment?<br></span>\n<span class=\"paragraph-sentence\">Woman: Yes. I didn’t think I could use it on board.<br></span>\n<span class=\"paragraph-sentence\">Man: Sure you can. I always use mine when I fly<br></span>\n<span class=\"paragraph-sentence\">Woman: I’m too tired for that. I think <span class=\"q1226-1\">I’ll take a nap</span>.<br></span>\n<span class=\"paragraph-sentence\">Man: Well, <span class=\"q1227-1\">I’m hungry</span>. I hope they serve a meal <span class=\"q1225-1\">on this flight</span>.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/JpuMG.mp3', null),
(553, 24, 'Questions 68 - 70:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: Dựa trên buổi phỏng vấn của chúng ta ngày hôm qua, tôi muốn giao cho cô công việc trong công ty chúng tôi. <br></span>\n<span class=\"paragraph-sentence\">W: Thật đúng là tin vui, ông Morrison. Khi nào tôi bắt đầu?<br></span>\n<span class=\"paragraph-sentence\">M: Cô sẽ phải ký hợp đồng trước đã, nhưng cô có thể bắt đầu vào tuần sau. <br></span>\n<span class=\"paragraph-sentence\">W: Tôi hoàn thành công việc hiện tại của mình vào thứ Sáu này, nên như vậy cũng tốt.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: Based on our interview yesterday, <span class=\"q1135-1\">I would like to offer you a job in our company.</span> <br></span>\n<span class=\"paragraph-sentence\">W: That\'s great news, Mr. Morrison. When do I start?<br></span>\n<span class=\"paragraph-sentence\">M: You\'ll have to sign the contract first, but <span class=\"q1136-1\">you should be able to start next week.</span> <br></span>\n<span class=\"paragraph-sentence\">W: <span class=\"q1137-1\">I finish my current job this Friday,</span> so that would be great.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_3/MqK0E.mp3', null),
(554, 24, 'Questions 71 - 73:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Khách hàng hãy chú ý! Một chiếc điện thoại bị mất vừa được tìm thấy ở quầy thực phẩm đông lạnh, dãy số 10. Nếu bạn nghĩ chiếc điện thoại này có thể là của bạn, xin hãy đến văn phòng dịch vụ khách hàng để nhận lại nó. Và khách hàng thân mến đừng quên hôm nay có chương trình bán hàng đặc biệt cho sản phẩm táo và lê. Chúng là trái cây tươi từ nông trại và đang được bán với giá rất rất thấp, chỉ 1 đô một kilo. Vì thế, hãy nhanh chân đến khu vực nông sản và chất đầy giỏ hàng của bạn với táo và lê. Các vị bố mẹ, đừng quên rằng con của các vị cần ăn nhiều trái cây tươi để khỏe mạnh. Với khách hàng có thẻ thành viên câu lạc bộ khách hàng được hưởng ưu đãi của chương trình này. Nếu bạn chưa có thẻ, hãy nhanh chóng đến phòng dịch vụ khách hàng để đăng ký thẻ câu lạc bộ thành viên ngay hôm nay.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q589-1\">Attention shoppers!</span> A lost cell phone has been found in the <span class=\"q589-2\">frozen food</span> section, aisle 10. <span class=\"q590-1\">If you think this cell phone may be yours, please go to the customer service office to claim it.</span> Don\'t forget shoppers, there\'s a special sale today on <span class=\"q589-3\">apples and pears</span>. They\'re fresh from the farm and are selling at the low, low price of just one dollar a kilo. So hurry to the produce section and load up on <span class=\"q589-3\">apples and pears</span>. Parents, don\'t forget that your children need to eat plenty of fresh fruit to stay healthy. <span class=\"q591-1\">Only customers with a Shoppers\' Club membership card can take advantage of this special sale.</span> If you don\'t have a card, hurry to the customer service office to sign up for your shoppers\' club membership today.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/Hxbwz.mp3', null),
(555, 24, 'Questions 74 - 76:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Bộ phim đặc biệt tối nay sẽ bắt đầu sau 15 phút nữa. Sẽ có một suất chiếu thứ hai vào lúc 11 giờ tối. Vui lòng mua vé ở quầy bán vé ít nhất 5 phút trước khi suất chiếu bắt đầu. Suất chiếu sẽ kéo dài 2 tiếng 45 phút. Thức ăn có thể mua trước khi bộ phim bắt đầu hoặc trong lúc chuyển cảnh ở giữa phim. Quý khách được yêu cầu không vào khán phòng khi bộ phim đã bắt đầu.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">W: Tonight\'s feature film will begin in just fifteen minutes. There will be a second showing at 11:00 p.m. Please buy your tickets at the ticket counter at least five minutes before the show starts. <span class=\"q500-1\">The show will last for two hours and forty-five minutes.</span> <span class=\"q501-1\">Refreshments can be purchased before the movie begins or during the intermission, which will occur half way through the film.</span> Patrons are asked not to enter the auditorium once the film has begun.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/9mTBk.mp3', null),
(556, 24, 'Questions 77 - 79:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Do thời tiết thay đổi thất thường ở một số điểm đến của chúng ta, một số lượng lớn chuyến bay sẽ được hủy hoặc hoãn lại. Chuyến bay số 777, 778 và 779 đã được hủy và hành khách sẽ được sắp xếp lên chuyến bay khác vào tối nay. Chuyến bay 776, 789 và 790 sẽ bị hoãn lại vô thời hạn. Chúng tôi sẽ sớm thông báo lịch bay dời lại cho quý khách. Nếu bạn cần khởi hành ngay lập tức, chúng tôi đề nghị quý khách kiểm tra với các công ty lữ hành nội địa để tìm chuyến bay sẽ cất cánh trong suốt ngày hôm nay. Chúng tôi chân thành xin lỗi vì sự bất tiện này. Để tiện cho quý khách, phòng chờ ở tầng một sẽ phục phụ nước và thức ăn nhẹ miễn phí. Quý khách nên đến đó chờ nếu quý khách nghĩ việc đó thích hợp.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q688-1\">Due to the unanticipated weather changes at several of our scheduled destinations, a number of flights will either be cancelled or severely delayed.</span> <span class=\"q689-1\">Flight numbers 777, 778, and 779 have been cancelled</span> and passengers will be rescheduled for different flights later this evening. Flight numbers 776, 789, and 790 have been delayed indefinitely. We will have their rescheduled times available for you shortly. <span class=\"q690-1\">If you need to depart immediately, we suggest checking with your local travel agent to find alternative routes available throughout the day.</span> We sincerely apologize for the inconvenience caused. For you convenience, the lounge on the first floor will serve complimentary drinks and snacks. You are invited to wait there if you deem it fitting to do so.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/TXStP.mp3', null),
(557, 24, 'Questions 80 - 82:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tôi hy vọng tất cả các bạn đã có một chuyến bay tốt đẹp. Tôi biết các bạn chắc chắn rất mệt do lệch múi giờ nhưng chúng tôi có một ngày với rất nhiều tiết mục được lên lịch cho các bạn. Đầu tiên, các bạn sẽ nhận phòng khách sạn và nghỉ ngơi một chút. Sau đó, lúc 10 giờ, chúng ta sẽ gặp nhau dưới sảnh khách sạn và đi ra bờ biển. Khoảng 12 giờ, chúng ta sẽ ăn trưa tại một nhà hàng hải sản nổi tiếng. Thực đơn trưa nay là tôm hùm. Sau bữa trưa, chúng ta sẽ dành phần thời gian còn lại của ngày đi tham quan chợ bên bờ biển. Có rất nhiều thứ thú vị để xem và mua ở đó. Giờ, chúng ta sẽ đến khách sạn trong năm phút nữa. Xin tất cả các bạn ở yên tại chỗ cho  đên khi xe ngừng hẳn. Cảm ơn.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">I hope you all had a wonderful flight. I know that you must all be jetlagged, but we have a full day planned for you. <span class=\"q279-1\">First, you will check into the hotel</span> and freshen up a little. Then, at 10 o\'clock, we will all meet down at the hotel lobby and go for a drive out to the beachside. Around twelve o\'clock, we will have lunch at a famous seafood restaurant. On the menu this afternoon is lobster. After lunch, we will spend the entire day visiting the market by the seashore. There are many fun things to see and buy there. Now, we will be arriving at our hotel in five minutes. <span class=\"q278-1\">Would all of you stay in our seats until the bus has come to a complete stop?</span> Thank you.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/ZaNHH.mp3', null),
(558, 24, 'Questions 83 - 85:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Chào, Ông Hong. Đây là Denise Reynolds. Tôi có thể đã tìm được một người thuê nhà thích hợp cho căn hộ ông đang cố cho thuê lại qua công ty của tôi. Một nhà nghiên cứu đang đến thăm tại Đại học Forest có tên là Brad Patterson đã liên hệ tôi về nó. Ông ấy muốn thuê ngôi nhà của ông đến ngày 1 tháng 9. Um, ông đã yêu cầu tôi tìm một ai đó để lấy căn hộ đến cuối tháng 9, nhưng ... um, ít người đã thể hiện sự quan tâm. Đây là tốt nhất tôi có thể làm. Ông Patterson muốn đến thăm căn hộ của ông tuần này. Tôi biết ông làm việc vào thứ Năm và thứ Sáu, vậy cuối tuần thì sao? Ông ấy đã nhắc rằng ông ấy rảnh vào chiều thứ Bảy. Hãy gọi tôi tại 555-0394 để cho tôi biết thời gian nào sẽ là tốt nhất.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Hello, Mr. Hong. It\'s Denise Reynolds. <span class=\"q1042-1\">I may have found a suitable tenant for the apartment you are trying to sublease through my firm</span>. A visiting researcher at Forest University named Brad Patterson contacted me about it. He wants to rent your home until September 1. Um, <span class=\"q1043-1\">you asked me to find someone to take the apartment until the end of September</span>, but ... um, few people have shown interest. <span class=\"q1043-2\">This is the best I can do</span>. Mr. Patterson would like to visit your unit this week. <span class=\"q1044-1\">I know you work on Thursday and Friday, so how about on the weekend? He mentioned that he was free on Saturday afternoon</span>. Call me at 555-0394 to let me know what time would be best.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/as7mE.mp3', null),
(559, 24, 'Questions 86 - 88:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Mấy bài kiểm tra của tôi hôm nay rất khó. Tôi có 3 bài kiểm tra. Vào buổi sáng, tôi có bài kiểm tra môn tiếng Pháp. Với tôi, tiếng Pháp rất khó, đặc biệt là về chính tả. Tôi không thể nào nhớ nổi là mình có cần thêm chữ \"e\" ở cuối từ hay không, mấy thứ đại loại như vậy. Sau đó, sau giờ trưa, tôi có bài kiểm tra lịch sử. Tôi không thể nào nhớ nổi những ngày tháng mà tôi đã học trước giờ kiểm tra. Lịch sử là môn khó nhất vì tôi thấy nó chán ngắt. Cuối cùng, vào buổi chiều, tôi có bài kiểm tra toán. Nó khó nhưng toán lại là môn học yêu thích của tôi nên tôi nghĩ tôi làm nó khá tốt. Tôi giỏi toán và thường được điểm cao nên tôi chắc là mình sẽ có điểm tốt. Trong học kỳ trước, tôi đạt điểm cao nhất trong lớp đấy.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">My exams today were so difficult. I had three exams. <span class=\"q247-1\">In the morning, I had a French exam.</span> French is really difficult for me, especially French spelling. I can never remember if I need an extra \"e\" at the end of words and that kind of thing. Then, after lunch I had a history exam. I couldn\'t remember any of the dates that I studied before the exam. <span class=\"q248-1\">History is the most difficult subject because I find it boring.</span> Finally, in the afternoon I had a math exam. It was difficult, but <span class=\"q249-1\">math is my favorite subject,</span> so I think I did pretty well on the exam. I\'m good at math and I usually get high grades, so I\'m sure I\'ll get a good score. Last semester, I got the best grade in my class.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/mPzTo.mp3', null),
(560, 24, 'Questions 89 - 91:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Chúng tôi thay đổi tên nhưng vẫn giữ lời hứa của mình! Trong nhiều thập niên qua, Villa Hospitalis đã cung cấp dịch vụ chăm sóc y tế chất lượng tốt nhất cho người nghèo và người có thu nhập thấp. Đã đến lúc tạo dựng hình ảnh riêng để mọi người đều biết những gì chúng tôi làm. Đó là lý do chúng tôi đổi tên bệnh viện thành bệnh viện Albert Schweitzer. Lấy cảm hứng từ công việc của bác sĩ Schweitzer vĩ đại, chúng tôi thay đổi cam kết của mình thành sự xuất sắc và chất lượng, cung cấp nhiều dịch vụ hơn và đặt ra tiêu chuẩn mới cho việc điều trị bệnh. Bệnh viện Albert Schweitzer... một cái tên khác cho những kết quả khả quan!</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">We\'re changing our name... but we\'re keeping our promises! For decades, <span class=\"q611-1\">Villa Hospitalis has been providing low-income and indigent people with the highest quality medical care.</span> <span class=\"q612-1\">It\'s time to create a separate identity,</span> so people will recognize what we do. That\'s why <span class=\"q610-1\">we\'re changing the name of our facility to the Albert Schweitzer Hospital.</span> Inspired by the work of the great Dr. Schweitzer, we have renewed our commitment to excellence and quality, offering more services and setting new standards for medical treatment. The Albert Schweitzer Hospital... another name for positive results!</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/NUsNs.mp3', null),
(561, 24, 'Questions 92 - 94:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Chào, tôi là Pete Patterson ở Hair Apparent. Nếu việc rụng tóc khiến cho bạn cảm thấy buồn, thì tôi đã có tin vui cho bạn. Hair Apparent có thể phục hồi tóc bạn một cách tự nhiên mà không cần đến đồ nối, kem thoa hay phẫu thuật đau đớn. Các bác sĩ giàu kinh nghiệm ở Hair Apparent đã kết hợp việc sử dụng tóc từ những phần khác của cơ thể với gel mọc tóc được cấp bằng sáng chế để cho bạn một mái đầu tự nhiên chỉ trong vòng 6 đến 8 tuần. Cuộc hẹn của tôi với bác sĩ Barringer ở Hair Apparent diễn ra nhanh chóng và dễ dàng. Tôi thoải mái ngồi xem DVD trong khi bác sĩ Barringer kiểm tra da đầu và bắt đầu cuộc điều trị không gây đau đớn gì. Các bạn, đây là quyết định đúng đắn nhất mà tôi đã từng đưa ra. Mái đầu gần như trụi của tôi giờ được bao phủ với mái tóc dày, mềm mà nói thật là trông còn đẹp hơn trước khi bị rụng tóc. Vợ tôi không tin nổi vào mắt! Hãy gọi ngay Hair Apparent ở số 555-1209 để được tư vấn miễn phí, hoặc ghé thăm một trong hai địa điểm của họ là 123 đường Main ở khu trung tâm hoặc số 345 đường Pine ở phía đông. Nói với họ là Pete Patterson giới thiệu bạn đến và bạn sẽ được giảm 20%. Đừng chờ đợi! Hãnh hành động ngay! Tin tôi đi, các bạn sẽ cảm thấy vui vì mình đã làm vậy.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Hi, Pete Patterson here for Hair Apparent. If hair loss has got you feeling blue, then I\'ve got good news for you. <span class=\"q52-1\">Hair Apparent can restore your hair naturally, without plugs, lotions, or painful surgery.</span> Hair Apparent\'s experienced doctors combine the use of hair from other parts of your body with their patented growth gel to give you a full, natural-looking head of hair within six- to eight-weeks. My appointment with Dr. Barringer at Hair Apparent was smooth and easy. I relaxed and watched DVD\'s while Dr. Barringer examined my scalp, then painlessly started treatment. Guys, this was the best decision I have ever made. <span class=\"q54-1\">My nearly bald head</span> is now covered with thick, rich, soft hair that honestly looks better than it did before it fell out. My wife can\'t believe it! Call Hair Apparent at 555-1209 today for a free consultation, or visit one of their two locations: 123 Main Street downtown or 345 Pine Street on the east side. Tell \'em Pete Patterson sent you, and you\'ll get 20 percent off. Don\'t wait! Act now! Trust me, you\'ll be glad you did.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/JnWoI.mp3', null),
(562, 24, 'Questions 95 - 97:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Mọi người đã làm thủ tục xong hết chưa? Nếu rồi, xin hãy tập trung chú ý. Tôi có một thông báo ngắn cho mọi người. Nếu bạn có thể lật sang trang thứ hai của hành trình mà bạn nhận được trên xe buýt trên đường chúng ta đến đây, bạn sẽ thấy lịch trình của chúng ta cho ngày mai. Như bạn thấy, chúng ta sẽ gặp nhau tại sảnh vào 8 giờ 50 sáng để đi Cảng Piney, cách đây khoảng 45 phút. Vì vậy, hãy chắc chắn rằng bạn sẽ ăn sáng sớm. Tôi không muốn để người khác chờ đợi. Tôi cũng muốn nói rằng vì Bảo tàng Globe đang được tân trang lại, nên thay vào đó chúng ta sẽ ghé thăm khu chợ ở địa phương. Và sau đó, chúng ta sẽ đi đến Green Gallery nổi tiếng. Sau đó, mọi thứ sẽ theo lịch trình như cũ. Nếu bạn có bất kỳ câu hỏi nào, vui lòng đến nói chuyện với tôi. Nếu không, bạn có thể đi.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">M: <span class=\"q778-1\">Has everyone checked in?</span> If so, may I have your attention? I just have a quick announcement to make. If you could turn to the second page of the itinerary you received on the bus on our way here, you’ll notice our schedule for tomorrow. As you can see, we’ll be meeting in the lobby by 8:50 in the morning to head toward Piney Harbor, which is about 45 minutes away from here. So make sure that you have your breakfast early. I don’t want to keep others waiting. <span class=\"q780-1\">I also want to mention that because of the renovations at the Globe Museum, we’ll visit the local market instead. And then, we’ll go to the famous Green Gallery.</span> Everything will be by the schedule after that. If you have any questions, feel free to come and talk to me. If not, you’re free to go.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/wfYIh.mp3', '/server/uploads/image/de-thi-thu-toeic-ma-de-fever-thi-thu-toeic-online/question_95_97.png'),
(563, 24, 'Questions 98 - 100:', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Vợ tôi, Gail, và tôi vừa mới mua một ngôi nhà đẹp. Nó có một khu vườn rộng và một cái sân cho bọn trẻ cùng chú chó. Nó gần trường học trong tỉnh, nơi mà Gail đang dạy và nó gần nhiều cửa hàng cùng một trung tâm thể thao. Bọn trẻ rất thích bơi và đá banh, nên việc này sẽ rất tuyệt cho chúng. Bên trong là một nhà bếp, phòng khách, phòng ăn và phòng tắm. Trên lầu là phòng ngủ của chúng tôi cùng với 2 phòng ngủ riêng cho bọn trẻ. Chúng đang rất mong đợi việc được quyền chọn giấy dán tường để trang trí cho căn phòng. Không gian rất rộng rãi và chúng tôi rất vui khi lần đầu tiên được sở hữu ngôi nhà của riêng mình. Chúng tôi đã quá mệt mỏi trước việc phải trả tiền nhà cho người khác. Chúng tôi biết mình sẽ thích việc sống ở đây.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q254-1\">My wife Gail and I</span> have recently purchased a beautiful home. It has a large garden and a yard for the kids and dog. <span class=\"q255-1\">It\'s near the local school where Gail teaches, and it is near several shops</span> and a sports center. The kids are crazy about swimming and soccer, so it\'s going to be great for them. Inside there\'s a kitchen, living room, dining room and bathroom. <span class=\"q253-1\">Upstairs there\'s our bedroom plus seperate bedrooms for <span class=\"q254-2\">our two kids.</span></span> They are looking forward to choosing their own wallpaper to decorate their rooms. There\'s plenty of room, and we\'re happy to be first-time homeowners. We were so tired of paying rent to other people. We\'re going to enjoy living here.</span></p>', 'https://tienganhmoingay.com/static/ToeicTests/audios/Practice_Tests/Part_4/wUqjU.mp3', null),
(564, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">New Marketing Plan for Infant Formula</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">According to a recent market research study by the Korean Survey Research Association, about 70% of <span class=\"q46-1\">mothers</span> of infants and toddlers find it hard to make a _____(1) decision on infant formula due to the picky tastes of their children, who often reject infant formulas.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">The new marketing plan aims to invite _____(2) mothers to a focus group discussion to allow them to try our infant formula product on their children. Meanwhile, mothers will be interviewed based on their children’s reaction to the product and asked for their ideas on how to improve it.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">_____(3). Once we have secured enough of them, the plan will be reviewed by the finance team to determine its budget _____(4) it gains final approval by Jamison Sears, the marketing director.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Kế hoạch tiếp thị mới cho Infant Formula</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Theo nghiên cứu thị trường do Hội Nghiên Cứu Khảo Sát Hàn Quốc, khoảng 70% mẹ của trẻ sơ sinh và trẻ đang tập đi rất khó đưa ra quyết định mua những loại sữa bột công thức cho trẻ bởi vì những sở thích về vị bột của trẻ, những người mà thường không chịu mua sữa bột công thức cho trẻ.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Kế hoạch tiếp thị mới nhằm mục đích mời các bà mẹ này tham gia thảo luận nhóm để giúp họ thử những sản phẩm công thức cho trẻ này cho con của họ. Trong lúc đó, những bà mẹ sẽ được phỏng vấn dựa trên phản ứng của con họ với sản phẩm và tham khảo ý kiến của họ về cách cải thiện sản phẩm.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Nhóm tiếp thị đang trong quá trình liên lạc với người được phỏng vấn. Một khi chúng tôi đã bảo đảm đủ số khách hàng, kế hoạch sẽ được nhóm tài chính xem xét để xác định ngân sách miễn là nó được sự chấp thuận cuối cùng của Jamison Sears, giám đốc tiếp thị.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">New Marketing Plan for Infant Formula</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">According to a recent market research study by the Korean Survey Research Association, about 70% of <span class=\"q46-1\">mothers</span> of infants and toddlers find it hard to make a _____(1) decision on infant formula due to the picky tastes of their children, who often reject infant formulas.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">The new marketing plan aims to invite _____(2) mothers to a focus group discussion to allow them to try our infant formula product on their children. Meanwhile, mothers will be interviewed based on their children’s reaction to the product and asked for their ideas on how to improve it.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">_____(3). Once we have secured enough of them, the plan will be reviewed by the finance team to determine its budget _____(4) it gains final approval by Jamison Sears, the marketing director.</span></p>', null, null),
(565, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">As the largest and fastest _____(1) community development group,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">we invite qualified professionals for our urban _____(2) project. Your mandate is to set the overall strategic direction for housing development, including sales and marketing. The ideal candidate must have a passion to deliver results in a dynamic market environment.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">You must have at least 5 years of relevant industry experience. You will be able to demonstrate an excellent record of successful implementation and sustainable growth.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">This leadership position is expected to attract candidates of the highest _____(3) Successful candidates will live in Indonesia and enjoy a highly competitive remuneration package, including traveling allowances.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To apply for the position, please submit your resume along with a cover letter by November 17, 2007 to hodevelop@attg.com.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Với tư cách là nhóm phát triển cộng đồng lớn nhất và mở rộng nhanh nhất,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">chúng tôi muốn mời những chuyên gia làm việc cho dự án làm mới khu đô thị. Quyền hạn của bạn là đặt ra hướng phát triển chiến lược chung cho việc phát triển nhà, bao gồm việc bán và tiếp thị. Ứng  viên lý tưởng phải có niềm đam mê muốn truyền tải những thành quả trong môi trường kinh doanh năng động.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Bạn phải có ít nhất 5 năm kinh nghiệm trong ngành liên quan. Bạn phải có khả năng thể hiện được việc thực hiện thành công và phát triển bền vững.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Vị trí lãnh đạo này sẽ thu hút những ứng viên chất lượng tốt nhất. Ứng viên thành công sẽ sống ở Indonesia và tận hưởng gói phúc lợi lương thưởng hấp dẫn, bao gồm trợ cấp đi lại.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Để nộp đơn  cho vị trí này, xin vui lòng nộp sơ yếu lý lịch cùng với thư xin việc trước ngày 17 tháng 11 năm 2007 đến hodevelop@attg.com.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">As the largest and fastest _____(1) community development group,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">we invite qualified professionals for our urban _____(2) project. Your mandate is to set the overall strategic direction for housing development, including sales and marketing. The ideal candidate must have a passion to deliver results in a dynamic market environment.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">You must have at least 5 years of relevant industry experience. You will be able to demonstrate an excellent record of successful implementation and sustainable growth.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">This leadership position is expected to attract candidates of the highest _____(3) Successful candidates will live in Indonesia and enjoy a highly competitive remuneration package, including traveling allowances.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To apply for the position, please submit your resume along with a cover letter by November 17, 2007 to hodevelop@attg.com.</span></p>', null, null),
(566, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">You are Cordially Invited</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dogorail would like to invite its business associates to the 25th Dogorail Transport and Logistics Exhibition scheduled for November 9 to 11 in Prague. Dogorail will be displaying its products and services on the main floor of the Zidenic Convention Center <span class=\"q167-1\">_____</span>(1) the three-day event. And there will be a special presentation by Dogorail CEO Miroslav Sergeyev on the final night. <span class=\"q167-1\">_____</span>(2). Representatives from Dogorail will be in attendance to assist visitors with their queries. Private <span class=\"q167-1\">_____</span>(3) on any of our offerings are welcome if you wish to obtain advice about your particular requirements.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To confirm your attendance to this event, please return the enclosed form, _____(4) filled out and with your signature appended, on or before April 30.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Thân Mời Các Bạn</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dogorail mời các đối tác kinh doanh đến với Triển Lãm Vận Chuyển và Hậu Cần Dogorail lần thứ 25 được lên lịch tổ chức từ ngày 9 đến 11 tháng 11 tại Prague. Dogorail sẽ trưng bày các sản phẩm và dịch vụ tại tầng chính của Trung Tâm Hội Nghị Zidenic xuyên suốt sự kiện kéo dài 3 ngày. Và sẽ có một bài thuyết trình đặc biệt bởi Giám đốc điều hành của Dogorail, Microslav Sergeyev vào đêm cuối cùng. Ông ấy sẽ thảo luận về những dự án đường sắt gần đây tại Moldova, Bulgaria, và Hy Lạp. Những đại diện từ Dogorail sẽ có mặt để hỗ trợ giải đáp câu hỏi cho khách tham dự. Chúng tôi hoan nghênh các buổi tư vấn riêng tư về bất kỳ sản phẩm hay dịch vụ nào của chúng tôi nếu bạn muốn nhận lời khuyên phù hợp với những yêu cầu cụ thể của bạn.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Để xác nhận tham dự sự kiện này, vui lòng gửi lại mẫu đơn được đính kèm, được điền vào đầy đủ và có chữ ký của bạn, vào ngày hoặc trước ngày 30 tháng 4.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">You are Cordially Invited</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dogorail would like to invite its business associates to the 25th Dogorail Transport and Logistics Exhibition scheduled for November 9 to 11 in Prague. Dogorail will be displaying its products and services on the main floor of the Zidenic Convention Center <span class=\"q167-1\">_____</span>(1) the three-day event. And there will be a special presentation by Dogorail CEO Miroslav Sergeyev on the final night. <span class=\"q167-1\">_____</span>(2). Representatives from Dogorail will be in attendance to assist visitors with their queries. Private <span class=\"q167-1\">_____</span>(3) on any of our offerings are welcome if you wish to obtain advice about your particular requirements.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To confirm your attendance to this event, please return the enclosed form, _____(4) filled out and with your signature appended, on or before April 30.</span></p>', null, null),
(567, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Thank you for choosing to fly Trinata Airlines. We ask all passengers _____(1) their itinerary with Trinata Air within 48 hours of your flight time, as it is possible that weather conditions and other unforeseen events could lead to flight cancellations.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To improve service in the future, at each _____(2) that Trinata serves, we are distributing short satisfaction surveys to arriving passengers.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">These surveys are completely optional. We hope you have a satisfactory experience flying with Trinata, and we will do our best to serve you _____(3) you arrive at your final destination.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Cám ơn quý khách đã chọn hãng hàng không Trinata Airlines. Chúng tôi yêu cầu tất cả hành khách xác nnhận lịch trình của họ với Trinata Air trong vòng 48 giờ trước giờ bay vì có thể điều kiện thời tiết và những sự việc bất ngờ khác có thể dẫn đến việc hủy chuyến bay.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Để cải thiện dịch vụ trong tương lai, ở mỗi địa điểm mà Trinata phục vụ, chúng tôi đang phát những bản khảo sát mức độ hài lòng cho các hành khách đến nơi.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Bảng khảo sát này hoàn toàn không bắt buộc. Chúng tôi hy vọng quý khách có một trải nghiệm hài lòng khi bay với Trinata, và chúng tôi sẽ cố gắng hết mình để phục vụ quý khách cho đến khi quý khách đến điểm đến cuối cùng.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Thank you for choosing to fly Trinata Airlines. We ask all passengers _____(1) their itinerary with Trinata Air within 48 hours of your flight time, as it is possible that weather conditions and other unforeseen events could lead to flight cancellations.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To improve service in the future, at each _____(2) that Trinata serves, we are distributing short satisfaction surveys to arriving passengers.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">These surveys are completely optional. We hope you have a satisfactory experience flying with Trinata, and we will do our best to serve you _____(3) you arrive at your final destination.</span></p>', null, null),
(568, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Nathan Chen 6:03 P.M. <br></span>\n<span class=\"paragraph-sentence\">Kacey Co.’s brand-launching show in England will take place next month! This London launching show is highly anticipated by the board due to the huge success of our brand launching in Norway last year. How are things going?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:06 P.M. <br></span>\n<span class=\"paragraph-sentence\">We received the <span class=\"q632-1\">fragrance</span> collection from our factory in India and it is ready for display. Now, we are waiting for the new Kacey’s <span class=\"q632-2\">skincare</span> line to arrive from Germany.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:10 P.M. <br></span>\n<span class=\"paragraph-sentence\">There will be a slight delay in the shipments.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:12 P.M. <br></span>\n<span class=\"paragraph-sentence\"><span class=\"q633-1\"><span class=\"q634-1\">A severe rainstorm here has been going on for a few days, and no overseas transportation is operational</span>.</span> The good news is that all the products are safely packed and ready to go.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:15 P.M. <br></span>\n<span class=\"paragraph-sentence\">Will this affect our brand-launching party schedule?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:16 P.M. <br></span>\n<span class=\"paragraph-sentence\"><span class=\"q635-1\">It most likely won’t because there is still a month left until the grand opening, and the storm will pass in a couple of days</span>.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Nathan Chen 6:18 P.M. <br></span>\n<span class=\"paragraph-sentence\">That is nice to hear.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:20 P.M. <br></span>\n<span class=\"paragraph-sentence\">Mr. Calen, please keep me updated on all the shipping information.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:23 P.M. <br></span>\n<span class=\"paragraph-sentence\">Of course. I will let you know as soon as possible.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Nathan Chen 6:03 P.M. <br></span>\n<span class=\"paragraph-sentence\">Chương trình giới thiệu thương hiệu Kacey Co. tại Anh sẽ diễn ra vào tháng tới! Chương trình ra mắt ở London này được đánh giá cao bởi hội đồng quản trị do sự thành công lớn của việc tung ra sản phẩm thương hiệu của chúng ta tại Na Uy năm ngoái. Mọi việc thế nào rồi?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:06 P.M. <br></span>\n<span class=\"paragraph-sentence\">Chúng tôi đã nhận được bộ sưu tập nước hoa từ nhà máy của chúng ta ở Ấn Độ và sẵn sàng để mang đi trưng bày. Hiện tại, chúng tôi đang chờ dòng sản phẩm chăm sóc da mới của Kacey đến từ Đức.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:10 P.M. <br></span>\n<span class=\"paragraph-sentence\">Hàng sẽ đến trễ một tí.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:12 P.M. <br></span>\n<span class=\"paragraph-sentence\">Một cơn bão lớn đã diễn ra trong vài ngày và không có phương tiện giao thông nào ở nước ngoài hoạt động. Tin vui là tất cả các sản phẩm của chúng ta được đóng gói an toàn và đã sẵn sàng để chuyển đi.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:15 P.M. <br></span>\n<span class=\"paragraph-sentence\">Điều này có ảnh hưởng đến kế hoạch ra mắt thương hiệu của chúng ta không?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:16 P.M. <br></span>\n<span class=\"paragraph-sentence\">Khả năng là sẽ không ảnh hưởng vì vẫn còn một tháng nữa mới khai trương, và cơn bão sẽ đi qua trong một vài ngày tới.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Nathan Chen 6:18 P.M. <br></span>\n<span class=\"paragraph-sentence\">Thật tốt khi nghe điều đó.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:20 P.M. <br></span>\n<span class=\"paragraph-sentence\">Anh Calen, hãy giúp tôi cập nhật các thông tin giao hàng nhé.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:23 P.M. <br></span>\n<span class=\"paragraph-sentence\">Tất nhiên rồi. Tôi sẽ cho bạn biết sớm nhất có thể.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Nathan Chen 6:03 P.M. <br></span>\n<span class=\"paragraph-sentence\">Kacey Co.’s brand-launching show in England will take place next month! This London launching show is highly anticipated by the board due to the huge success of our brand launching in Norway last year. How are things going?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:06 P.M. <br></span>\n<span class=\"paragraph-sentence\">We received the <span class=\"q632-1\">fragrance</span> collection from our factory in India and it is ready for display. Now, we are waiting for the new Kacey’s <span class=\"q632-2\">skincare</span> line to arrive from Germany.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:10 P.M. <br></span>\n<span class=\"paragraph-sentence\">There will be a slight delay in the shipments.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:12 P.M. <br></span>\n<span class=\"paragraph-sentence\"><span class=\"q633-1\"><span class=\"q634-1\">A severe rainstorm here has been going on for a few days, and no overseas transportation is operational</span>.</span> The good news is that all the products are safely packed and ready to go.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:15 P.M. <br></span>\n<span class=\"paragraph-sentence\">Will this affect our brand-launching party schedule?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:16 P.M. <br></span>\n<span class=\"paragraph-sentence\"><span class=\"q635-1\">It most likely won’t because there is still a month left until the grand opening, and the storm will pass in a couple of days</span>.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Nathan Chen 6:18 P.M. <br></span>\n<span class=\"paragraph-sentence\">That is nice to hear.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Douglas Stanfield 6:20 P.M. <br></span>\n<span class=\"paragraph-sentence\">Mr. Calen, please keep me updated on all the shipping information.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sajan Calen 6:23 P.M. <br></span>\n<span class=\"paragraph-sentence\">Of course. I will let you know as soon as possible.</span></p>', null, null),
(569, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To: All employees <br></span>\n<span class=\"paragraph-sentence\">From: Tylor Johns <br></span>\n<span class=\"paragraph-sentence\">Date: May 20 <br></span>\n<span class=\"paragraph-sentence\">Subject: Parking lot</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q539-1\">This is an announcement that the management has approved a plan to repave the employee parking lot.</span> The work will begin on June 1. <span class=\"q541-1\">During the work, employees are not allowed to use the parking lot.</span> We strongly recommend taking public transportation. Employees can use a parking lot in the Commerce building for $100 a month. The work should be done by June 15.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Please accept our apologies for the inconvenience and thank for your cooperation.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tylor Johns</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Facilities Manager</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Gửi: Tất cả nhân viên <br></span>\n<span class=\"paragraph-sentence\">Từ: Tylor Johns <br></span>\n<span class=\"paragraph-sentence\">Ngày: 20 tháng 5 <br></span>\n<span class=\"paragraph-sentence\">Tiêu đề: Bãi gửi xe</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Đây là thông báo rằng ban quản lý đã chấp thuận kế hoạch lát sàn lại bãi gửi xe của nhân viên. Thi công sẽ bắt đầu vào ngày 1 tháng 6. Trong khi thi công, nhân viên không được sử dụng bãi gửi xe này. Chúng tôi đề xuất các bạn đi phương tiện công cộng. Nhân viên có thể sử dụng bãi gửi xe ở tòa nhà Thương Mại với giá 100 đô một tháng. Thi công sẽ hoàn tất trước ngày 15 tháng 6.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Xin hãy chấp nhận lời xin lỗi của chúng tôi vì sự bất tiện này và cảm ơn sự hợp tác của mọi người.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tylor Johns</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Quản lý Cơ sở vật chất</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To: All employees <br></span>\n<span class=\"paragraph-sentence\">From: Tylor Johns <br></span>\n<span class=\"paragraph-sentence\">Date: May 20 <br></span>\n<span class=\"paragraph-sentence\">Subject: Parking lot</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q539-1\">This is an announcement that the management has approved a plan to repave the employee parking lot.</span> The work will begin on June 1. <span class=\"q541-1\">During the work, employees are not allowed to use the parking lot.</span> We strongly recommend taking public transportation. Employees can use a parking lot in the Commerce building for $100 a month. The work should be done by June 15.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Please accept our apologies for the inconvenience and thank for your cooperation.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tylor Johns</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Facilities Manager</span></p>', null, null),
(570, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><u><strong>Knitting Class Series: Spring 2008</strong></u></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Instructor: Bobbie Purnell <br></span>\n<span class=\"paragraph-sentence\">First Session: February 11, 25, March 3, 10 12-2 PM  <br></span>\n<span class=\"paragraph-sentence\">Second Session: March 17, 24, April 7, 14 12-2 PM <br></span>\n<span class=\"paragraph-sentence\"><span class=\"q435-1\">Room: To be determined</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">This is a wonderful opportunity for beginners to learn about the art of knitting and for experienced knittes to perfect their skills. Experienced and advanced-level knitters are also welcome.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Fee: $15 for knitting materials. Fee will be waived if you bring your own materials. (cash only) <br></span>\n<span class=\"paragraph-sentence\">Capacity: 15 beginner-level students and up to 5 advanced-level students <br></span>\n<span class=\"paragraph-sentence\">Register: Please contact Bianca Mona, New Haven Diversity &amp; Community Center at ws_div-comm@knitting.com or <span class=\"q436-1\">stop by 128 Zankel Building.</span></span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><u><strong>Các lớp học đan: Mùa xuân 2008</strong></u></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Giáo viên hướng dẫn: Bobbie Purnell<br></span>\n<span class=\"paragraph-sentence\">Phần đầu tiên: 11, 25 tháng 2, 3, 10 tháng 3 12 đến 2 giờ chiều<br></span>\n<span class=\"paragraph-sentence\">Phần thứ hai: 17, 24 tháng 3, 7, 14 tháng 4 12 đến 2 giờ chiều<br></span>\n<span class=\"paragraph-sentence\">Phòng: chưa xác định</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Đây là cơ hội tuyệt vời cho những người mới bắt đầu tìm hiểu về nghệ thuật đan và những người đan có kinh nghiệm hoàn thiện kỹ năng của mình. Những người đan có kinh nghiệm và trình độ cao cũng được chào đón.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Phí: 15 đô cho vật liệu đan. Chúng tôi sẽ không tính phí nếu bạn mang vật liệu của mình đến. (Chỉ nhận tiền mặt)<br></span>\n<span class=\"paragraph-sentence\">Sỉ số: 15 học viên trình độ vỡ lòng và 5 học viên trình độ cao<br></span>\n<span class=\"paragraph-sentence\">Đăng ký: Vui lòng liên hệ Bianca Mona, New Haven Diversity &amp; Community Center theo địa chỉ ws_div-comm@knitting.com hoặc đến 128 Zankel Building.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><u><strong>Knitting Class Series: Spring 2008</strong></u></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Instructor: Bobbie Purnell <br></span>\n<span class=\"paragraph-sentence\">First Session: February 11, 25, March 3, 10 12-2 PM  <br></span>\n<span class=\"paragraph-sentence\">Second Session: March 17, 24, April 7, 14 12-2 PM <br></span>\n<span class=\"paragraph-sentence\"><span class=\"q435-1\">Room: To be determined</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">This is a wonderful opportunity for beginners to learn about the art of knitting and for experienced knittes to perfect their skills. Experienced and advanced-level knitters are also welcome.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Fee: $15 for knitting materials. Fee will be waived if you bring your own materials. (cash only) <br></span>\n<span class=\"paragraph-sentence\">Capacity: 15 beginner-level students and up to 5 advanced-level students <br></span>\n<span class=\"paragraph-sentence\">Register: Please contact Bianca Mona, New Haven Diversity &amp; Community Center at ws_div-comm@knitting.com or <span class=\"q436-1\">stop by 128 Zankel Building.</span></span></p>', null, null),
(571, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\"><strong>Bugs and Beans Coffee Shop</strong><br></span>\n<span class=\"paragraph-sentence\">Museum of Natural Science<br></span>\n<span class=\"paragraph-sentence\">401 E. Rosser Ave.,<br></span>\n<span class=\"paragraph-sentence\">Columbus, OH 45021<br></span>\n<span class=\"paragraph-sentence\">Tel: (502) 235-4678  Fax: (502) 235-4688</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Mr. Tomi Galoob, <br></span>\n<span class=\"paragraph-sentence\">Galoob Ceramics <br></span>\n<span class=\"paragraph-sentence\">PO Box 356 <br></span>\n<span class=\"paragraph-sentence\">Frisbie, NY 02165</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dear Mr. Galoob,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Thank you for sending me a copy of your latest ceramics catalog. <span class=\"q472-1\">You have been sending us your catalog here at the museum for several years now,</span> and I always look forward to reading it. I was amazed yet again at the variety and creativity that you have displayed in your work. Your vases and bowls are quite exquisite! They look so realistic. They really do resemble the plants and animals that they are modeled after. <span class=\"q473-1\">I would like to order 50 more of the ladybug bowls. They are perfect for holding sugar cubes,</span> but unfortunately we have had a lot of breakages this year. However, it was the scorpion cups that really grabbed my attention. According to the catalog, they are available in small, medium, and a limited number of extra-large sizes. I am interested in purchasing approximately 25 of the extra-large scorpion cups. If they are popular, I may consider ordering more, if the museum has the budget. <span class=\"q470-1\">Please send me information on your available stock.</span> <span class=\"q471-1\">I would appreciate receiving the information by fax.</span> I look forward to hearing from you, and hope that we will be able to continue doing business for a long time to come.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sincerely,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Linda Trump, <br></span>\n<span class=\"paragraph-sentence\">Manager, Bugs and Beans Coffee Shop</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\"><strong>Tiệm cà phê Bugs and Beans</strong><br></span>\n<span class=\"paragraph-sentence\">Bảo tàng Khoa học Tự nhiên<br></span>\n<span class=\"paragraph-sentence\">401 E. Rosser Ave.,<br></span>\n<span class=\"paragraph-sentence\">Columbus, OH 45021<br></span>\n<span class=\"paragraph-sentence\">Điện thoại: (502) 235-4678  Fax: (502) 235-4688</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Ông Tomi Galoob,<br></span>\n<span class=\"paragraph-sentence\">Galoob Ceramics<br></span>\n<span class=\"paragraph-sentence\">PO Box 356<br></span>\n<span class=\"paragraph-sentence\">Frisbie, NY 02165</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Ông Galoob thân mến,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Cảm ơn đã gửi cho tôi một bản danh mục những mẫu đồ sứ mới nhất của ông. Ông đã gửi danh mục cho chúng tôi tại viện bảo tàng này nhiều năm nay, và tôi luôn mong chờ được đọc nó. Tuy nhiên, một lần nữa tôi lại ngạc nhiên trước sự đa dạng và sáng tạo mà ông đã thể hiện trong công việc của mình. Những bình hoa và chén bát rất tinh xảo! Chúng trông như thật. Chúng trông giống hệt những cây cỏ và con vật mà chúng mô phỏng theo. Tôi muốn đặt thêm 50 cái chén hình bọ cánh cam. Chúng rất thích hợp cho việc đựng những viên đường, nhưng không may, rất nhiều cái bị vỡ vào năm nay. Tuy nhiên, chính những cái tách hình bọ cạp mới thật sự thu hút sự chú ý của tôi. Theo như danh mục, chúng có cỡ nhỏ, vừa và một số lượng giới hạn ở cỡ cực lớn. Tôi muốn mua khoảng 25 chiếc tách hình bọ cạp cỡ cực lớn. Nếu chúng được ưa chuộng, tôi có thể cân nhắc đặt thêm, nếu bảo tàng có ngân sách. Vui lòng gửi cho tôi thông tin về những món hàng mà ông có. Tôi rất cảm kích nếu nhận được thông  tin qua fax. Tôi rất mong được nghe tin từ ông và hy vọng chúng ta có thể tiếp tục làm ăn với nhau lâu dài.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Trân trọng,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Linda Trump<br></span>\n<span class=\"paragraph-sentence\">Giám đốc, Tiệm cà phê Bugs and Beans</span></p>', '<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\"><strong>Bugs and Beans Coffee Shop</strong><br></span>\n<span class=\"paragraph-sentence\">Museum of Natural Science<br></span>\n<span class=\"paragraph-sentence\">401 E. Rosser Ave.,<br></span>\n<span class=\"paragraph-sentence\">Columbus, OH 45021<br></span>\n<span class=\"paragraph-sentence\">Tel: (502) 235-4678  Fax: (502) 235-4688</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Mr. Tomi Galoob, <br></span>\n<span class=\"paragraph-sentence\">Galoob Ceramics <br></span>\n<span class=\"paragraph-sentence\">PO Box 356 <br></span>\n<span class=\"paragraph-sentence\">Frisbie, NY 02165</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dear Mr. Galoob,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Thank you for sending me a copy of your latest ceramics catalog. <span class=\"q472-1\">You have been sending us your catalog here at the museum for several years now,</span> and I always look forward to reading it. I was amazed yet again at the variety and creativity that you have displayed in your work. Your vases and bowls are quite exquisite! They look so realistic. They really do resemble the plants and animals that they are modeled after. <span class=\"q473-1\">I would like to order 50 more of the ladybug bowls. They are perfect for holding sugar cubes,</span> but unfortunately we have had a lot of breakages this year. However, it was the scorpion cups that really grabbed my attention. According to the catalog, they are available in small, medium, and a limited number of extra-large sizes. I am interested in purchasing approximately 25 of the extra-large scorpion cups. If they are popular, I may consider ordering more, if the museum has the budget. <span class=\"q470-1\">Please send me information on your available stock.</span> <span class=\"q471-1\">I would appreciate receiving the information by fax.</span> I look forward to hearing from you, and hope that we will be able to continue doing business for a long time to come.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sincerely,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Linda Trump, <br></span>\n<span class=\"paragraph-sentence\">Manager, Bugs and Beans Coffee Shop</span></p>', null, null),
(572, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Hays Marketing, Inc. Merging with MarketingExperts, Inc. </strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Hays Marketing, Inc. announced last week that its expertise in marketing data processing will be merged with <span class=\"q453-1\">marketing publications created by MarketingExperts, Inc.</span> The two companies are among the most prosperous marketing research firms nationwide. <br></span>\n<span class=\"paragraph-sentence\">Dr. Ethan McCaskey, vice president of Hays Marketing, states that the two firms will function independently but <span class=\"q454-1\">will be able to offer marketing professionals useful research data and practical training.</span> He also adds that the merge will enable them to take advantage of the best employees from both companies. <br></span>\n<span class=\"paragraph-sentence\">For the last few years, the two research firms have been separately devising innovative methods to enhance their services. Now that they share the same objective - to discover what works in marketing - <span class=\"q452-1\">they are hoping better to serve their clientele with the merger.</span></span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Công ty Hays Marketing sát nhập với công ty MarketingExperts</strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Công ty Hays Marketing tuần trước đã thông báo rằng chuyên môn của công ty trong xử lý dữ liệu tiếp thị sẽ được kết hợp với ấn phẩm  tiếp thị được tạo ra bởi công ty MarketingExperts. Hai công ty nằm trong số những công ty nghiên cứu tiếp thị thành công trên toàn quốc.<br></span>\n<span class=\"paragraph-sentence\">Tiến sĩ Ethan McCaskey, phó chủ tịch của Hays Marketing cho biết hai công ty sẽ hoạt động độc lập nhưng sẽ có thể cung cấp cho các chuyên viên tiếp thị những dữ liệu nghiên cứu hữu ích và đào tạo thực tiễn. Ông còn cho biết thêm rằng sự sát nhập sẽ cho phép họ tận dụng nhân viên giỏi nhất của cả hai công ty.<br></span>\n<span class=\"paragraph-sentence\">Trong mấy năm vừa qua, hai công ty nghiên cứu này đã độc lập phát minh ra các phương pháp sáng tạo để củng cố các dịch vụ của họ. Vì họ có chung mục tiêu - khám phá xem cái gì sẽ có hiệu quả trong tiếp thị - họ hy vọng sẽ phục vụ khách hàng tốt hơn với sự sát nhập này.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Hays Marketing, Inc. Merging with MarketingExperts, Inc. </strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Hays Marketing, Inc. announced last week that its expertise in marketing data processing will be merged with <span class=\"q453-1\">marketing publications created by MarketingExperts, Inc.</span> The two companies are among the most prosperous marketing research firms nationwide. <br></span>\n<span class=\"paragraph-sentence\">Dr. Ethan McCaskey, vice president of Hays Marketing, states that the two firms will function independently but <span class=\"q454-1\">will be able to offer marketing professionals useful research data and practical training.</span> He also adds that the merge will enable them to take advantage of the best employees from both companies. <br></span>\n<span class=\"paragraph-sentence\">For the last few years, the two research firms have been separately devising innovative methods to enhance their services. Now that they share the same objective - to discover what works in marketing - <span class=\"q452-1\">they are hoping better to serve their clientele with the merger.</span></span></p>', null, null),
(573, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:40] <br></span>\n<span class=\"paragraph-sentence\">Can I get an  update from everyone on the promotion project for N-Genz Auto? Our next presentation’s been moved up to Tuesday, August 10.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Barry Carr [11:42] <br></span>\n<span class=\"paragraph-sentence\">The script changes for the TV commercial will be done this afternoon. Other than that, I’m just waiting for production to give me permission to proceed.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:45] <br></span>\n<span class=\"paragraph-sentence\">Barry, our first choice for the lead actor backed out, so I’m waiting to hear back from the talent agency about a replacement. But still, we can proceed with our shoot on July 18 at Snappy Studios.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:47] <br></span>\n<span class=\"paragraph-sentence\">Thank you both. What about the online campaign? My contact at N-Genz Auto is eager to see what’s been done.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Willa Hopkins [11:50]  <br></span>\n<span class=\"paragraph-sentence\">Well, I’m in the final stages of developing the Web site. I need about a week more to do the finishing touches, but I’m quite confident we’ll be done in time.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:54]<br></span>\n<span class=\"paragraph-sentence\">Good news. I called the agency and was told that my second choice for a performer can do the job.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Barry Carr [11:55] <br></span>\n<span class=\"paragraph-sentence\">Great, Dustin. I’ll send you a copy of the finished script tonight. By the way, I can’t make it on the 18th as I need to be at a client meeting, so I’ll send Brianna Johns in my place.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:57] <br></span>\n<span class=\"paragraph-sentence\">No problem, Barry. <span class=\"q682-1\">I’ll get in touch with her shortly to make further arrangements.</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:58] <br></span>\n<span class=\"paragraph-sentence\">It looks like we are <span class=\"q681-1\">on the right track</span>. Dustin, keep me posted on your schedule. <span class=\"q683-1\">Willa, could you send me a link to the site so I can see the progress so far?</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:59] <br></span>\n<span class=\"paragraph-sentence\">Understood. I’ll send you the most current schedule I have right now.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Willa Hopkins [11:59] <br></span>\n<span class=\"paragraph-sentence\">OK, Michelle. I can send you the link now. Just bear in mind there are some issues to work out.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:40] <br></span>\n<span class=\"paragraph-sentence\">Tôi có thể nhận được thông tin cập nhật từ tất cả mọi người về dự án quảng cáo cho N-Genz Auto không? Bài thuyết trình tiếp theo của chúng ta được chuyển đến thứ ba, ngày 10 tháng 8.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Barry Carr [11:42] <br></span>\n<span class=\"paragraph-sentence\">Kịch bản thay đổi cho quảng cáo truyền hình sẽ được thực hiện chiều nay. Ngoài ra, tôi đang chờ đợi bên sản xuất cho phép tôi tiếp tục.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:45] <br></span>\n<span class=\"paragraph-sentence\">Barry, người mà chúng ta ưu tiên chọn cho vai chiễn chính đã rút, vì vậy tôi đang chờ đợi thông tin từ công ty tài năng cho người thay thế. Tuy nhiên, chúng ta vẫn có thể tiến hành chụp hình vào ngày 18 tháng 7 tại Snappy Studios.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:47] <br></span>\n<span class=\"paragraph-sentence\">Cảm ơn cả hai bạn. Còn chiến dịch trực tuyến thì sao? Người tôi liên hệ bên N-Genz Auto mong muốn biết những gì đã được thực hiện.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Willa Hopkins [11:50]  <br></span>\n<span class=\"paragraph-sentence\">Vâng, tôi đang ở giai đoạn cuối của việc phát triển trang Web. Tôi cần khoảng một tuần nữa để hoàn thành phần còn lại, nhưng tôi khá tự tin rằng chúng ta sẽ hoàn thành đúng thời gian.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:54] <br></span>\n<span class=\"paragraph-sentence\">Tin tốt đây. Tôi đã gọi cho bên công ty và được cho biết rằng diễn viên ưu tiên thứ hai mà tôi chọn có thể thực hiện công việc.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Barry Carr [11:55] <br></span>\n<span class=\"paragraph-sentence\">Tuyệt vời, Dustin. Tôi sẽ gửi cho bạn một bản sao của kịch bản hoàn thành vào tối nay. Nhân tiện, tôi sẽ không đến được vào ngày 18 vì tôi cần phải có mặt tại một cuộc họp khách hàng, vì vậy tôi sẽ nhờ Brianna Johns đến thay cho tôi.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:57] <br></span>\n<span class=\"paragraph-sentence\">Không thành vấn đề, Barry. Tôi sẽ sớm liên hệ với cô ấy để sắp xếp.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:58] <br></span>\n<span class=\"paragraph-sentence\">Có vẻ như chúng ta đang đi đúng hướng đó. Dustin, hãy cứ cập nhật lịch trình của bạn cho tôi nhé. Willa, bạn có thể gửi cho tôi đường dẫn đến trang web để tôi có thể nhìn thấy làm đến đâu rồi không?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:59] <br></span>\n<span class=\"paragraph-sentence\">Hiểu rồi. Tôi sẽ gửi cho bạn lịch trình mới nhất mà tôi có ngay bây giờ.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Willa Hopkins [11:59]  <br></span>\n<span class=\"paragraph-sentence\">OK, Michelle. Tôi có thể gửi cho bạn đường dẫn ngay bây giờ. Chỉ cần nhớ là có một số vấn đề cần giải quyết.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:40] <br></span>\n<span class=\"paragraph-sentence\">Can I get an  update from everyone on the promotion project for N-Genz Auto? Our next presentation’s been moved up to Tuesday, August 10.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Barry Carr [11:42] <br></span>\n<span class=\"paragraph-sentence\">The script changes for the TV commercial will be done this afternoon. Other than that, I’m just waiting for production to give me permission to proceed.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:45] <br></span>\n<span class=\"paragraph-sentence\">Barry, our first choice for the lead actor backed out, so I’m waiting to hear back from the talent agency about a replacement. But still, we can proceed with our shoot on July 18 at Snappy Studios.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:47] <br></span>\n<span class=\"paragraph-sentence\">Thank you both. What about the online campaign? My contact at N-Genz Auto is eager to see what’s been done.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Willa Hopkins [11:50]  <br></span>\n<span class=\"paragraph-sentence\">Well, I’m in the final stages of developing the Web site. I need about a week more to do the finishing touches, but I’m quite confident we’ll be done in time.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:54]<br></span>\n<span class=\"paragraph-sentence\">Good news. I called the agency and was told that my second choice for a performer can do the job.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Barry Carr [11:55] <br></span>\n<span class=\"paragraph-sentence\">Great, Dustin. I’ll send you a copy of the finished script tonight. By the way, I can’t make it on the 18th as I need to be at a client meeting, so I’ll send Brianna Johns in my place.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:57] <br></span>\n<span class=\"paragraph-sentence\">No problem, Barry. <span class=\"q682-1\">I’ll get in touch with her shortly to make further arrangements.</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Michelle Hanson [11:58] <br></span>\n<span class=\"paragraph-sentence\">It looks like we are <span class=\"q681-1\">on the right track</span>. Dustin, keep me posted on your schedule. <span class=\"q683-1\">Willa, could you send me a link to the site so I can see the progress so far?</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dustin Rodriguez [11:59] <br></span>\n<span class=\"paragraph-sentence\">Understood. I’ll send you the most current schedule I have right now.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"> </span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Willa Hopkins [11:59] <br></span>\n<span class=\"paragraph-sentence\">OK, Michelle. I can send you the link now. Just bear in mind there are some issues to work out.</span></p>', null, null),
(574, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Do you enjoy working outdoors? Do you thrive in a physically demanding work environment? Then Gateway Contractors has the perfect job for you!</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q184-1\">We\'re looking for young, energetic individuals to work on Gateway\'s latest construction project:</span> the Maplewood Gymnasium. Successful candidates will be responsible for unloading supply trucks and distributing supplies to various key points around the site. No previous construction experience is necessary, but applicants must be able to work well with other people.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Applications are available at www.gatewaycontractors.com. <span class=\"q185-1\">To schedule an interview, contact Bruno Morton,</span> the Construction Site Supervisor, at 245-698-7895. Please, no calls after 9 p.m.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Bạn có thích làm việc ngoài trời không? Bạn thích làm việc trong một môi trường đòi hỏi về thể lực? Vậy thì Gateway Constractors có một công việc hoàn hảo cho bạn.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Chúng tôi đang tìm kiếm những người trẻ nhiệt huyết để làm việc cho xây dựng dự án mới nhất của Gateway: phòng tập Maplewood. Những ứng viên được tuyển sẽ chịu trách nhiệm về việc bốc dỡ những xe chở vật liệu và phân phối chúng tới những điểm chính trong công trường. Không cần kinh nghiệm về xây dựng, nhưng các ứng viên phải làm việc tốt với người khác.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Đơn đăng ký có sẵn trên trang www.gatewaycontractors.com. Để hẹn phỏng vấn, liên lạc với ông Bruno Morton, Giám sát công trường thi công ở số 245-698-7895. Xin vui lòng không gọi sau 9 giờ tối.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Do you enjoy working outdoors? Do you thrive in a physically demanding work environment? Then Gateway Contractors has the perfect job for you!</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q184-1\">We\'re looking for young, energetic individuals to work on Gateway\'s latest construction project:</span> the Maplewood Gymnasium. Successful candidates will be responsible for unloading supply trucks and distributing supplies to various key points around the site. No previous construction experience is necessary, but applicants must be able to work well with other people.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Applications are available at www.gatewaycontractors.com. <span class=\"q185-1\">To schedule an interview, contact Bruno Morton,</span> the Construction Site Supervisor, at 245-698-7895. Please, no calls after 9 p.m.</span></p>', null, null),
(575, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">TO: Fatima Sukarno (sukfat@balinesiaindustries.com)<br></span>\n<span class=\"paragraph-sentence\">FROM: Vinnie Deniro (vinde@vertbleu.com)<br></span>\n<span class=\"paragraph-sentence\">SUBJECT: Upcoming visit<br></span>\n<span class=\"paragraph-sentence\">ATTACHMENT: product specifications</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dear Ms. Sukarno,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q874-1\">Thank you for responding so quickly to my inquiry about visiting your manufacturing plant in Jakarta</span>. I will ask my assistant Theresa Montovani to go ahead and make travel arrangements for me and my colleague Sheryl Stein to travel there from New York on February 24.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q876-1\">As Vert-Bleu Beauty is interested in pursuing a production contract with your company, I think it is important that we meet with you and see your facilities in person</span>. -[1]-.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q875-1\">Our cosmetics are guaranteed to be completely natural and environmentally sound, so our production guidelines would be rather strict</span>. -[2]-. I am attaching a list of specifications for the manufacturing process of our beauty products. You and your executive staff can have a look through them and see if everything is clear.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Once our flights have been booked, Ms. Montovani will send you, or your secretary, a final itinerary. -[3]-. We thank you kindly for offering us hotel accommodation and a driver service during our stay, and gratefully accept. -[4]-. Our assistants can coordinate to work out any details.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">I am looking forward to meeting with you, and I do hope that we will be able to work together on this venture.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Regards,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Vinnie Deniro<br></span>\n<span class=\"paragraph-sentence\">Product development director, Vert-Bleu Beauty</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">ĐẾN: Fatima Sukarno (sukfat@balinesiaindustries.com)<br></span>\n<span class=\"paragraph-sentence\">TỪ: Vinnie Deniro (vinde@vertbleu.com)<br></span>\n<span class=\"paragraph-sentence\">CHỦ ĐỀ: Chuyến thăm sắp tới<br></span>\n<span class=\"paragraph-sentence\">ĐÍNH KÈM: các chỉ số sản phẩm</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Kính gửi Cô Sukarno,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Cảm ơn vì đã phản hồi thật nhanh tới câu hỏi của tôi về việc đến thăm nhà máy sản xuất của cô ở Jakarta. Tôi sẽ nhờ trợ lý của tôi Theresa Montovani tiếp tục và thực hiện các sắp xếp du lịch cho tôi và đồng nghiệp của tôi Sheryl Stein để đi đến đó từ New York vào ngày 24 tháng 2.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Vì Vert-Bleu Beauty có hứng thú với việc theo đuổi một hợp đồng sản xuất với công ty của cô, tôi nghĩ là rất quan trọng cho việc chúng tôi gặp cô và trực tiếp xem các cơ sở của cô. -[1]-.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Các mỹ phẩm của chúng tôi đảm bảo là hoàn toàn tự nhiên và tốt cho môi trường, nên các quy định sản xuất của chúng tôi khá chặt chẽ. -[2]-. Tôi sẽ đính kèm một danh sách các chỉ số cho quy trình sản xuất của các mỹ phẩm của chúng tôi. Cô và các viên chức của cô có thể xem qua chúng và xem liệu mọi thứ có rõ ràng không.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Một khi các chuyến bay của chúng tôi đã được đặt, Cô Montovani sẽ gửi cô, hoặc thư ký của cô, một bản lộ trình chính thức. -[3]-. Chúng tôi hân hạnh cảm ơn vì đã đề nghị cho chúng tôi chỗ nghỉ khách sạn và một dịch vụ tài xế trong kì nghỉ của chúng tôi, và vui lòng chấp nhận. -[4]-. Các trợ lý của chúng tôi có thể phối hợp để làm rõ bất kì chi tiết nào.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tôi mong gặp cô, và tôi mong chúng ta sẽ có thể làm việc với nhau trong dự án kinh doanh này.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Hân hạnh,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Vinnie Deniro<br></span>\n<span class=\"paragraph-sentence\">Giám đốc phát triển sản phẩm, Vert-Bleu Beauty</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">TO: Fatima Sukarno (sukfat@balinesiaindustries.com)<br></span>\n<span class=\"paragraph-sentence\">FROM: Vinnie Deniro (vinde@vertbleu.com)<br></span>\n<span class=\"paragraph-sentence\">SUBJECT: Upcoming visit<br></span>\n<span class=\"paragraph-sentence\">ATTACHMENT: product specifications</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dear Ms. Sukarno,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q874-1\">Thank you for responding so quickly to my inquiry about visiting your manufacturing plant in Jakarta</span>. I will ask my assistant Theresa Montovani to go ahead and make travel arrangements for me and my colleague Sheryl Stein to travel there from New York on February 24.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q876-1\">As Vert-Bleu Beauty is interested in pursuing a production contract with your company, I think it is important that we meet with you and see your facilities in person</span>. -[1]-.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q875-1\">Our cosmetics are guaranteed to be completely natural and environmentally sound, so our production guidelines would be rather strict</span>. -[2]-. I am attaching a list of specifications for the manufacturing process of our beauty products. You and your executive staff can have a look through them and see if everything is clear.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Once our flights have been booked, Ms. Montovani will send you, or your secretary, a final itinerary. -[3]-. We thank you kindly for offering us hotel accommodation and a driver service during our stay, and gratefully accept. -[4]-. Our assistants can coordinate to work out any details.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">I am looking forward to meeting with you, and I do hope that we will be able to work together on this venture.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Regards,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Vinnie Deniro<br></span>\n<span class=\"paragraph-sentence\">Product development director, Vert-Bleu Beauty</span></p>', null, null),
(576, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\">ANNOUNCEMENT: TIME CHANGE</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q513-1\">Tuesday\'s Movie Club meeting at the Megaplex cinema will be moved to Friday at 3:00 p.m.</span> We will be watching the movie The Wizard of Oz. It is the 20th time we have shown it. During the movie, we will serve popcorn and drinks at our usual low prices. Remember, as part of our special offer, <span class=\"q514-1\">this week you can bring one friend for free.</span> <span class=\"q515-1\">We have seating for only 300 people.</span> This is one of our most popular movies, so don\'t be late. We hope to see you soon.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\">THÔNG BÁO: THAY ĐỔI THỜI GIAN</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Buổi họp mặt câu lạc bộ điện ảnh vào thứ Ba tại rạp chiếu phim Megaplex sẽ được dời sang thứ Sáu lúc 3 giờ chiều. Chúng ta sẽ xem bộ phim Phù Thủy xứ Oz. Đây là lần thứ 20 chúng tôi chiếu bộ phim này. Trong lúc xem phim, chúng tôi sẽ phục vụ bắp rang và nước uống với giá thấp như thường lệ. Hãy nhớ rằng, là một phần của ưu đãi đặc biệt của chúng tôi, tuần này bạn có thể dẫn theo một người bạn miễn phí. Chúng tôi chỉ có chỗ ngồi cho 300 người. Đây là một trong những bộ phim được yêu thích nhất cả chúng tôi, vì thế đừng đến trễ. Chúng tôi hy vọng sẽ sớm được gặp lại các bạn.</span></p>', '<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\">ANNOUNCEMENT: TIME CHANGE</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q513-1\">Tuesday\'s Movie Club meeting at the Megaplex cinema will be moved to Friday at 3:00 p.m.</span> We will be watching the movie The Wizard of Oz. It is the 20th time we have shown it. During the movie, we will serve popcorn and drinks at our usual low prices. Remember, as part of our special offer, <span class=\"q514-1\">this week you can bring one friend for free.</span> <span class=\"q515-1\">We have seating for only 300 people.</span> This is one of our most popular movies, so don\'t be late. We hope to see you soon.</span></p>', null, null),
(577, 24, '<h3>Reading text:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Overdue Materials: </strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">- Book, Audio Books, Music CDs, Magazines:<br></span>\n<span class=\"paragraph-sentence\">*<span class=\"q542-1\">$0.10 per day per item</span> <br></span>\n<span class=\"paragraph-sentence\">*$5.00 maximum fine per item</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">- Video Cassettes &amp; DVDs: <br></span>\n<span class=\"paragraph-sentence\">*$1.00 per day per item <br></span>\n<span class=\"paragraph-sentence\">*$5.00 maximum fine per item</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong><span class=\"q543-1\">Lost or Damaged Materials:</span></strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">*Replacement cost plus $5.00 processing fee <br></span>\n<span class=\"paragraph-sentence\">*<span class=\"q544-1\">For items whose cost is undeterminable, the default replacement cost is $25.00 plus $5.00 processing fee.</span><br></span>\n<span class=\"paragraph-sentence\">*An exact replacement for a lost item will be accepted, but a $5.00 processing fee will still be assessed.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tài liệu quá hạn</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">- Sách, sách nghe, CD nhạc, tạp chí: <br></span>\n<span class=\"paragraph-sentence\">*0.10 đô mỗi ngày cho mỗi vật <br></span>\n<span class=\"paragraph-sentence\">*Phạt tối đa 5.00 đô cho mỗi vật</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">- Băng cassette và DVD: <br></span>\n<span class=\"paragraph-sentence\">*1.00 đô mỗi ngày cho mỗi vật <br></span>\n<span class=\"paragraph-sentence\">*Phạt tối đa 5.00 đô cho mỗi vật</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tài liệu bị thất lạc hoặc hư hỏng</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">*Chi phí thay thể cộng thêm 5.00 đô phí xử lý<br></span>\n<span class=\"paragraph-sentence\">*Đối với những vật không xác định được chi phí, chi phí thay thể mặc định là 25.00 đô cộng 5.00 đô phí xử lý <br></span>\n<span class=\"paragraph-sentence\">Vật thay thế y hệt vật bị thất lạc cũng được chấp nhận, nhưng vẫn tính 5.00 đô phí xử lý.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Overdue Materials: </strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">- Book, Audio Books, Music CDs, Magazines:<br></span>\n<span class=\"paragraph-sentence\">*<span class=\"q542-1\">$0.10 per day per item</span> <br></span>\n<span class=\"paragraph-sentence\">*$5.00 maximum fine per item</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">- Video Cassettes &amp; DVDs: <br></span>\n<span class=\"paragraph-sentence\">*$1.00 per day per item <br></span>\n<span class=\"paragraph-sentence\">*$5.00 maximum fine per item</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong><span class=\"q543-1\">Lost or Damaged Materials:</span></strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">*Replacement cost plus $5.00 processing fee <br></span>\n<span class=\"paragraph-sentence\">*<span class=\"q544-1\">For items whose cost is undeterminable, the default replacement cost is $25.00 plus $5.00 processing fee.</span><br></span>\n<span class=\"paragraph-sentence\">*An exact replacement for a lost item will be accepted, but a $5.00 processing fee will still be assessed.</span></p>', null, null),
(578, 24, '<h3>Reading text 1:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>MEMO</strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To: All new hires <br></span>\n<span class=\"paragraph-sentence\">From: Edwin Mallory, Human Resources Director <br></span>\n<span class=\"paragraph-sentence\">Re: Training session</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q244-1\">All new hires are required to attend a training session</span> which will take place on Friday, October 12 <span class=\"q243-1\">from 9:30 A.M until 3:30 P.M.</span> The session will be <strong><span class=\"q246-1\">conducted</span></strong> in Meeting Room 3, and lunch will be provided. During the session you will get an overview of company policies and procedures. You will also be updated on changes in the benefits package and learn about professional development opportunities you will be required to participate in so that you can keep up with changes in your field. Attendance at this training is mandatory for everyone hired since June of this year. There will be no excuses.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>THÔNG BÁO NỘI BỘ</strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Đến: Tất cả nhân viên mới tuyển<br></span>\n<span class=\"paragraph-sentence\">Từ: Edwin Mallory, Giám đốc phòng Nhân sự<br></span>\n<span class=\"paragraph-sentence\">Về việc: Buổi huấn luyện</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tất cả nhân viên mới được yêu cầu phải tham dự một buổi huấn luyện diễn ra vào thứ Sáu, ngày 12 tháng 12, từ 9 giờ 30 sáng đến 3 giờ 30 chiều. Buổi huấn luyện diễn ra tại phòng họp 3 và sẽ bao gồm một bữa ăn trưa. Trong suốt buổi huấn luyện, các bạn sẽ có cái nhìn tổng quan về chính sách và các quy định của công ty. Các bạn sẽ được cập nhật về những thay đổi trong gói phúc lợi và tìm hiểu về cơ hội phát triển nghề nghiệp mà bạn được yêu cầu tham gia để các bạn có thể bắt kịp những thay đổi trong lĩnh vực của mình. Việc tham dự buổi huấn luyện này là bắt buộc đối với tất cả nhân viên được tuyển từ tháng 6 năm nay. Không chấp nhận bất cứ lý do nào.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>MEMO</strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">To: All new hires <br></span>\n<span class=\"paragraph-sentence\">From: Edwin Mallory, Human Resources Director <br></span>\n<span class=\"paragraph-sentence\">Re: Training session</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><span class=\"q244-1\">All new hires are required to attend a training session</span> which will take place on Friday, October 12 <span class=\"q243-1\">from 9:30 A.M until 3:30 P.M.</span> The session will be <strong><span class=\"q246-1\">conducted</span></strong> in Meeting Room 3, and lunch will be provided. During the session you will get an overview of company policies and procedures. You will also be updated on changes in the benefits package and learn about professional development opportunities you will be required to participate in so that you can keep up with changes in your field. Attendance at this training is mandatory for everyone hired since June of this year. There will be no excuses.</span></p>', null, null),
(579, 24, '<h3>Reading text 1:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Autumn Leaf to Open Second Location in Buenos Aires</strong><br></span>\n<span class=\"paragraph-sentence\"><em>By Leonard Oldman</em></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Autumn Leaf Hotels has announced plans to open a second branch in Buenos Aires\' Liniers district. Autumn Leaf public relations director Angelo Suarez said that the new hotel will be more like a temporary apartment building for businesspeople visiting the city. \"<span class=\"q680-1\">There is a lot of demand from visitors who need to stay in Buenos Aires for long periods of time but don\'t wish to spend a fortune on a full-service hotel</span>,\" he said. He went on to say that the hotel will consist of large units with living areas as well as kitchens so that guests can prepare their own meals. <span class=\"q683-2\">Although the new hotel will not house a restaurant or offer room-service like the main branch in Monserrat</span>, there will be a 24-hour café on the ground floor, housekeeping staff, and a concierge desk. <span class=\"q681-2\">The hotel open sometime in August</span>, and prospective guests may make bookings or inquire about rates at www.autumnleafhotels.com.</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Autumn Leaf sẽ Khai trương Địa điểm thứ Hai ở Buenos Aires</strong><br></span>\n<span class=\"paragraph-sentence\"><em>Bởi Leonard Oldman</em></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Khách sạn Autumn Leaf đã thông báo các kế hoạch để khai trương một chi nhánh thứ hai ở quận Liniers của Buenos Aires. Giám đốc quan hệ công chúng Autumn Leaf Suarez đã nói rằng khách sạn mới sẽ giống như một tòa nhà chung cư tạm thời cho những nhà kinh doanh đến thăm thành phố. \"Có rất nhiều nhu cầu từ những vị khách đến thăm cần ở lại Buenos Aires cho các khoảng thời gian dài nhưng không muốn tiêu một gia tài cho một khách sạn dịch vụ đầy đủ,\" ông ấy đã nói. Ông ấy tiếp tục nói rằng khách sạn sẽ có các căn hộ lớn với các khu vực phòng khách cũng như bếp để các vị khách có thể chuẩn bị các bữa ăn của riêng họ. Tuy khách sạn mới sẽ không chứa một nhà hàng hoặc cung cấp dịch vụ phòng như chi nhánh chính ở Monserrat, sẽ có một tiệm cà phê 24 giờ ở tầng trệt, nhân viên dọn phòng, và một quầy tiền sảnh. Khách sạn sẽ mở một lúc nào đó trong tháng 8, và các vị khách sắp tới có thể thực hiện các đặt phòng hoặc hỏi về các giá tại www.autumnleafhotels.com.</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\"><strong>Autumn Leaf to Open Second Location in Buenos Aires</strong><br></span>\n<span class=\"paragraph-sentence\"><em>By Leonard Oldman</em></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Autumn Leaf Hotels has announced plans to open a second branch in Buenos Aires\' Liniers district. Autumn Leaf public relations director Angelo Suarez said that the new hotel will be more like a temporary apartment building for businesspeople visiting the city. \"<span class=\"q680-1\">There is a lot of demand from visitors who need to stay in Buenos Aires for long periods of time but don\'t wish to spend a fortune on a full-service hotel</span>,\" he said. He went on to say that the hotel will consist of large units with living areas as well as kitchens so that guests can prepare their own meals. <span class=\"q683-2\">Although the new hotel will not house a restaurant or offer room-service like the main branch in Monserrat</span>, there will be a 24-hour café on the ground floor, housekeeping staff, and a concierge desk. <span class=\"q681-2\">The hotel open sometime in August</span>, and prospective guests may make bookings or inquire about rates at www.autumnleafhotels.com.</span></p>', null, null),
(580, 24, '<h3>Reading text 1:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">June 4</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Marjorie Harkness<br></span>\n<span class=\"paragraph-sentence\">495 Rue Delacroix<br></span>\n<span class=\"paragraph-sentence\">New Orleans, Louisiana 70124</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dear Ms. Harkness,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">As you may have heard, Pinefrost Publishing will be releasing the sequel to my novel <em>Adriana\'s Song</em> this fall. The book will be entitled <span class=\"q532-3\"><em>Tony\'s Tune</em></span>, and <span class=\"q532-1\">I have enclosed a complimentary copy of my newest manuscript for you to look over</span>.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">I was asked to find someone to write a foreword for the book, and I immediately thought of you. <span class=\"q534-2\">You have given all of my novels very positive reviews in <em>Print Media Magazine</em></span>, and I appreciate your support very much. <span class=\"q530-1\">Would you be willing to write a short preface for the new book for me?</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Feel free to contact me at any time by mobile at 555-4009 or by e-mail at rorydansen@dvmail.com.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sincerely yours,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Rory Dansen</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">4 tháng 6</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Marjorie Harkness<br></span>\n<span class=\"paragraph-sentence\">495 Rue Delacroix<br></span>\n<span class=\"paragraph-sentence\">New Orleans, Louisiana 70124</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Kính gửi Cô Harkness,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Như cô đã có thể nghe thấy, Xuất bản Pinefrost sẽ ra mắt tập tiếp theo của tiểu thuyết của tôi <em>Bài hát của Adriana</em> mùa thu này. Cuốn sách sẽ được đặt tựa <em>Điệu nhạc của Tony</em>, và tôi đã gửi kèm một bản sao miễn phí của bản thảo mới nhất của tôi cho cô để xem qua.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Tôi đã được yêu cầu nhờ một người nào đó viết các lời nói đầu cho cuốn sách, và tôi lập tức nghĩ về cô. Cô đã cho mọi cuốn tiểu thuyết của tôi các đánh giá rất tích cực trong <em>Tạp chí Print Media</em>, và tôi cảm kích sự ủng hộ của cô rất nhiều. Cô có đồng ý viết các lời nói đầu ngắn cho cuốn sách mới cho tôi không?</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Hãy tự nhiên liên hệ tôi bất kì lúc nào bằng điện thoại di động tại 555-4009 hoặc bằng e-mail tại rorydansen@dvmail.com</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Hân hạnh,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Rory Dansen</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">June 4</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Marjorie Harkness<br></span>\n<span class=\"paragraph-sentence\">495 Rue Delacroix<br></span>\n<span class=\"paragraph-sentence\">New Orleans, Louisiana 70124</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Dear Ms. Harkness,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">As you may have heard, Pinefrost Publishing will be releasing the sequel to my novel <em>Adriana\'s Song</em> this fall. The book will be entitled <span class=\"q532-3\"><em>Tony\'s Tune</em></span>, and <span class=\"q532-1\">I have enclosed a complimentary copy of my newest manuscript for you to look over</span>.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">I was asked to find someone to write a foreword for the book, and I immediately thought of you. <span class=\"q534-2\">You have given all of my novels very positive reviews in <em>Print Media Magazine</em></span>, and I appreciate your support very much. <span class=\"q530-1\">Would you be willing to write a short preface for the new book for me?</span></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Feel free to contact me at any time by mobile at 555-4009 or by e-mail at rorydansen@dvmail.com.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Sincerely yours,</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Rory Dansen</span></p>', null, null),
(581, 24, '<h3>Reading text 1:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\"><strong><span style=\"font-size:20px;\">Report Card: MARY SMITH</span></strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"></p><p style=\"\"></p><table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px;\">\n	<tbody>\n		<tr>\n			<td><strong>Subject</strong></td>\n			<td>Grade</td>\n			<td>Comments</td>\n		</tr>\n		<tr>\n			<td>English 11</td>\n			<td>B</td>\n			<td>Mary\'s writing continues to improve.</td>\n		</tr>\n		<tr>\n			<td>Math 11</td>\n			<td>A</td>\n			<td>Excellent work, Mary!</td>\n		</tr>\n		<tr>\n			<td>Science 11</td>\n			<td>C</td>\n			<td>Mary needs to work much harder.</td>\n		</tr>\n		<tr>\n			<td>Music 11</td>\n			<td>A+</td>\n			<td>It\'s a pleasure to have Mary in my class!</td>\n		</tr>\n		<tr>\n			<td>Art 11</td>\n			<td>B</td>\n			<td>Please practice more with oil paints.</td>\n		</tr>\n		<tr>\n			<td>History 11</td>\n			<td>B-</td>\n			<td>A large improvement. Keep working!</td>\n		</tr>\n		<tr>\n			<td>Phys. Ed 11</td>\n			<td>A-</td>\n			<td>One of our top volleyball players!</td>\n		</tr>\n		<tr>\n			<td>Spanish 11</td>\n			<td>B+</td>\n			<td>Mary speaks quite well.</td>\n		</tr>\n	</tbody>\n</table><p></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\"><strong><span style=\"font-size:20px;\">Phiếu liên lạc: MARY SMITH</span></strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"></p><table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px;\">\n	<tbody>\n		<tr>\n			<td><strong>Môn học</strong></td>\n			<td>Điểm</td>\n			<td>Lời phê</td>\n		</tr>\n		<tr>\n			<td>Tiếng Anh 11</td>\n			<td>B</td>\n			<td>Kỹ năng viết của Mary tiếp tục tiến bộ.</td>\n		</tr>\n		<tr>\n			<td>Toán 11</td>\n			<td>A</td>\n			<td>Rất xuất sắc, Mary!</td>\n		</tr>\n		<tr>\n			<td>Khoa học 11</td>\n			<td>C</td>\n			<td>Mary cần học chăm chỉ hơn nữa.</td>\n		</tr>\n		<tr>\n			<td>Âm nhạc 11</td>\n			<td>A+</td>\n			<td>Tôi rất vui khi có Mary học lớp của mình!</td>\n		</tr>\n		<tr>\n			<td>Mĩ thuật 11</td>\n			<td>B</td>\n			<td>Hãy luyện tập vẽ tranh sơn dầu nhiều hơn.</td>\n		</tr>\n		<tr>\n			<td>Lịch sử 11</td>\n			<td>B-</td>\n			<td>Tiến bộ rất nhiều. Tiếp tục học chăm nhé!</td>\n		</tr>\n		<tr>\n			<td>Thể dục 11</td>\n			<td>A-</td>\n			<td>Một trong những tuyển thủ bóng chuyền xuất sắc nhất của chúng tôi!</td>\n		</tr>\n		<tr>\n			<td>Tiếng Tây Ban Nha 11</td>\n			<td>B+</td>\n			<td>Mary nói rất tốt.</td>\n		</tr>\n	</tbody>\n</table><p></p><p></p>', '<p class=\"reading-text-paragraph\" style=\"text-align: center;\"><span class=\"paragraph-sentence\"><strong><span style=\"font-size:20px;\">Report Card: MARY SMITH</span></strong></span></p>\n<p class=\"reading-text-paragraph\" style=\"\"></p><p style=\"\"></p><table border=\"1\" cellpadding=\"1\" cellspacing=\"1\" style=\"width:500px;\">\n	<tbody>\n		<tr>\n			<td><strong>Subject</strong></td>\n			<td>Grade</td>\n			<td>Comments</td>\n		</tr>\n		<tr>\n			<td>English 11</td>\n			<td>B</td>\n			<td>Mary\'s writing continues to improve.</td>\n		</tr>\n		<tr>\n			<td>Math 11</td>\n			<td>A</td>\n			<td>Excellent work, Mary!</td>\n		</tr>\n		<tr>\n			<td>Science 11</td>\n			<td>C</td>\n			<td>Mary needs to work much harder.</td>\n		</tr>\n		<tr>\n			<td>Music 11</td>\n			<td>A+</td>\n			<td>It\'s a pleasure to have Mary in my class!</td>\n		</tr>\n		<tr>\n			<td>Art 11</td>\n			<td>B</td>\n			<td>Please practice more with oil paints.</td>\n		</tr>\n		<tr>\n			<td>History 11</td>\n			<td>B-</td>\n			<td>A large improvement. Keep working!</td>\n		</tr>\n		<tr>\n			<td>Phys. Ed 11</td>\n			<td>A-</td>\n			<td>One of our top volleyball players!</td>\n		</tr>\n		<tr>\n			<td>Spanish 11</td>\n			<td>B+</td>\n			<td>Mary speaks quite well.</td>\n		</tr>\n	</tbody>\n</table><p></p>', null, null),
(582, 24, '<h3>Reading text 1:</h3>\n					\n					\n					\n					<div class=\"paragraph-p7\">\n						<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Murray (July 10) – The construction of the Rosemount Apartment Complex is now complete, and residents are flooding in. This new development is <strong><span class=\"q340-1\">animating</span></strong> the area and boosting the sales of nearby businesses.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Businesses in the Lamere Building, which is located in front of the apartment complex, are benefiting greatly. Among them is Murphy Pizza on the second floor. The owner of the pizzeria, Hillary Dembowski, reports that she has “seen a 200% increase in revenue.”</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Rosa Chisholm is the owner of Dream Bakers, a new bakery that opened its doors in the Lamere Building just yesterday. Ms. Chisholm is expecting a high return on her new business. “Everything seems to be working out positively.”</span></p>\n					</div>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Murray (10 tháng 7) - Công trình khu phức hợp Rosemount đã được hoàn thành, và người dân đang dọn vào dồn dập. Công trình mới này đang làm sống động khu vực và thúc đẩy doanh số bán hàng của các doanh nghiệp gần đó.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Các doanh nghiệp tại tòa nhà Lamere, nằm ở phía trước khu căn hộ phức hợp, đang được hưởng lợi rất nhiều. Trong số đó có Murphy Pizza ở tầng hai. Chủ cửa hàng bánh, Hillary Dembowski, cho biết cô “đã chứng kiến doanh thu tăng 200%.”</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Rosa Chisholm là chủ của Dream Bakers, một tiệm bánh mới mở cửa ở tòa nhà Lamere hôm qua. Bà Chisholm hy vọng sẽ đạt được lợi nhuận cao trong kinh doanh mới của bà ấy. “Mọi thứ dường như đang diễn ra rất tích cực.”</span></p>', '<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Murray (July 10) – The construction of the Rosemount Apartment Complex is now complete, and residents are flooding in. This new development is <strong><span class=\"q340-1\">animating</span></strong> the area and boosting the sales of nearby businesses.</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Businesses in the Lamere Building, which is located in front of the apartment complex, are benefiting greatly. Among them is Murphy Pizza on the second floor. The owner of the pizzeria, Hillary Dembowski, reports that she has “seen a 200% increase in revenue.”</span></p>\n<p class=\"reading-text-paragraph\" style=\"\"><span class=\"paragraph-sentence\">Rosa Chisholm is the owner of Dream Bakers, a new bakery that opened its doors in the Lamere Building just yesterday. Ms. Chisholm is expecting a high return on her new business. “Everything seems to be working out positively.”</span></p>', null, null);
